editor := ClipFormatter()

class ControlWrapper {
    ctrl := ""
    __New(host, type, opts := "", text := "") {
        this.ctrl := host.Add(type, opts, text)
    }
    Value {
        get => this.ctrl.Value
        set => this.ctrl.Value := value
    }
    On(event, handler) {
        this.ctrl.OnEvent(event, handler)
    }
    Enable(on) {
        this.ctrl.Opt(on ? "-Disabled" : "+Disabled")
    }
    Place(x?, y?, w?, h?) {
        this.ctrl.Move(x?, y?, w?, h?)
    }
}

class EditWrap extends ControlWrapper {
    __New(host, opts := "") {
        super.__New(host, "Edit", opts)
    }
    Value {
        get => this.ctrl.Value
        set => this.ctrl.Value := StrReplace(value, "`r`n", "`n")
    }
    LineCount {
        get {
            text := this.Value
            return text = "" ? 0 : StrSplit(text, "`n").Length
        }
    }
    Stats => Format("{} chars | {} lines", StrLen(this.Value), this.LineCount)
}

class ButtonWrap extends ControlWrapper {
    __New(host, opts, label, action) {
        super.__New(host, "Button", opts, label)
        DllCall("uxtheme\SetWindowTheme", "ptr", this.ctrl.Hwnd, "wstr", "DarkMode_Explorer", "ptr", 0)
        this.On("Click", action)
    }
    Value {
        get => this.ctrl.Text
        set => this.ctrl.Text := value
    }
}

class ClipFormatter {
    __New() {
        this.history := []
        this.future := []
        this.notice := ""
        this.gui := Gui("+Resize +MinSize420x260", "Clipboard Formatter")
        this.gui.BackColor := "141414"
        this.gui.SetFont("s10 cD8D8D8", "Segoe UI")
        DllCall("dwmapi\DwmSetWindowAttribute", "ptr", this.gui.Hwnd, "int", 20, "int*", 1, "int", 4)
        this.edit := EditWrap(this.gui, "x10 y10 w480 h230 Multi WantTab Background1E1E1E")
        this.edit.On("Change", this.OnEdited.Bind(this))
        this.transforms := Map()
        this.transforms["UPPER CASE"] := StrUpper
        this.transforms["lower case"] := StrLower
        this.transforms["Proper Case"] := StrTitle
        this.toolRow := []
        x := 10
        for label in ["UPPER CASE", "lower case", "Proper Case"] {
            fn := this.transforms[label]
            this.toolRow.Push(ButtonWrap(this.gui, Format("x{} y250 w104 h26", x), label, this.ApplyTransform.Bind(this, fn)))
            x += 110
        }
        this.undoBtn := ButtonWrap(this.gui, Format("x{} y250 w66 h26", x), "Undo", this.Undo.Bind(this))
        this.redoBtn := ButtonWrap(this.gui, Format("x{} y250 w66 h26", x + 72), "Redo", this.Redo.Bind(this))
        this.status := ControlWrapper(this.gui, "Text", "x10 y286 w480 cA8A8A8", "")
        this.gui.OnEvent("Escape", this.Close.Bind(this))
        this.gui.OnEvent("Close", this.Close.Bind(this))
        this.gui.OnEvent("Size", this.OnSize.Bind(this))
        HotIfWinActive("ahk_id " this.gui.Hwnd)
        Hotkey("^z", this.Undo.Bind(this))
        Hotkey("^y", this.Redo.Bind(this))
        HotIf()
        this.LoadClipboard()
        this.UpdateButtons()
        this.UpdateStatus()
        this.gui.Show("w500 h316")
    }
    LoadClipboard() {
        text := ""
        try
            text := A_Clipboard
        catch
            text := ""
        if (text = "") {
            this.notice := "Clipboard has no text - copy some text, then use the transform buttons"
            return
        }
        this.edit.Value := text
    }
    ApplyTransform(fn, *) {
        text := this.edit.Value
        if (text = "") {
            this.notice := "Nothing to format - the working text is empty"
            this.UpdateStatus()
            return
        }
        result := fn(text)
        if (result == text) {
            this.notice := "No change - text is already in that case"
            this.UpdateStatus()
            return
        }
        this.history.Push(text)
        this.future := []
        this.SetText(result)
    }
    SetText(text) {
        this.edit.Value := text
        A_Clipboard := StrReplace(text, "`n", "`r`n")
        this.notice := ""
        this.UpdateButtons()
        this.UpdateStatus()
    }
    Undo(*) {
        if !this.history.Length
            return
        this.future.Push(this.edit.Value)
        this.SetText(this.history.Pop())
    }
    Redo(*) {
        if !this.future.Length
            return
        this.history.Push(this.edit.Value)
        this.SetText(this.future.Pop())
    }
    OnEdited(*) {
        this.notice := ""
        this.UpdateStatus()
    }
    UpdateButtons() {
        this.undoBtn.Enable(this.history.Length > 0)
        this.redoBtn.Enable(this.future.Length > 0)
    }
    UpdateStatus() {
        line := this.edit.Stats
        if (this.notice != "")
            line .= "  |  " this.notice
        this.status.Value := line
    }
    OnSize(guiObj, minMax, width, height) {
        if (minMax = -1)
            return
        this.edit.Place(10, 10, width - 20, height - 86)
        rowY := height - 66
        x := 10
        for btn in this.toolRow {
            btn.Place(x, rowY)
            x += 110
        }
        this.undoBtn.Place(x, rowY)
        this.redoBtn.Place(x + 72, rowY)
        this.status.Place(10, height - 30, width - 20)
    }
    Close(*) {
        this.gui.Destroy()
        ExitApp()
    }
    __Delete() {
        try this.gui.Destroy()
    }
}

