class TextCommandDesk {
    __New() {
        this.title := "AHK v2.1 Text Command Desk"
        this.gui := Gui("+Resize +MinSize760x460", this.title)
        this.theme := DarkTheme(this.gui)
        this.gui.SetFont("s10 cE8E8E8", "Segoe UI")
        this.controls := Map()
        this.history := TextHistory(40)
        this.transforms := TransformRegistry()
        this.layout := FlowLayout(this.gui, this.controls)
        this.statsTimer := this.FlushStats.Bind(this)
        this.BuildTransforms()
        this.BuildGui()
        this.ApplyTheme()
        this.BindEvents()
    }

    Run() {
        this.LoadClipboard()
        this.gui.Show("w920 h620")
        this.theme.ApplyWindowChrome()
    }

    BuildGui() {
        this.controls["input"] := EditWrap(this.gui, "input", "x14 y14 w620 h430 -Wrap WantTab VScroll")
        this.controls["stats"] := StatusWrap(this.gui, "stats", "x14 y450 w620 h28")
        this.controls["copy"] := ButtonWrap(this.gui, "copy", "x650 y14 w130 h32", "Copy")
        this.controls["paste"] := ButtonWrap(this.gui, "paste", "x790 y14 w130 h32", "Load Clip")
        this.controls["undo"] := ButtonWrap(this.gui, "undo", "x650 y54 w130 h32", "Undo")
        this.controls["clear"] := ButtonWrap(this.gui, "clear", "x790 y54 w130 h32", "Clear")
        this.controls["commands"] := CommandPanelWrap(this.gui, "commands", "x650 y102 w270 h376", this.transforms)
        this.controls["input"].Focus()
        this.UpdateStats()
    }

    ApplyTheme() {
        for name, wrap in this.controls
            wrap.ApplyTheme(this.theme)
    }

    BuildTransforms() {
        this.transforms.Add("Trim Lines", TextTransform("Trim Lines", this.TrimLines.Bind(this)))
        this.transforms.Add("Deduplicate", TextTransform("Deduplicate", this.DeduplicateLines.Bind(this)))
        this.transforms.Add("Sort A-Z", TextTransform("Sort A-Z", this.SortLines.Bind(this)))
        this.transforms.Add("Reverse", TextTransform("Reverse", this.ReverseLines.Bind(this)))
        this.transforms.Add("Snake Case", TextTransform("Snake Case", this.SnakeCase.Bind(this)))
        this.transforms.Add("Upper", TextTransform("Upper", StrUpper))
        this.transforms.Add("Lower", TextTransform("Lower", StrLower))
    }

    BindEvents() {
        this.gui.OnEvent("Close", this.HandleClose.Bind(this))
        this.gui.OnEvent("Escape", this.HandleClose.Bind(this))
        this.gui.OnEvent("Size", this.HandleSize.Bind(this))
        this.controls["input"].On("Change", this.HandleInputChanged.Bind(this))
        this.controls["copy"].On("Click", this.CopyText.Bind(this))
        this.controls["paste"].On("Click", this.LoadClipboard.Bind(this))
        this.controls["undo"].On("Click", this.Undo.Bind(this))
        this.controls["clear"].On("Click", this.ClearText.Bind(this))
        this.controls["commands"].OnCommand(this.ApplyCommand.Bind(this))
    }

    HandleClose(*) {
        this.theme.Dispose()
        this.gui.Destroy()
        ExitApp()
    }

    HandleSize(guiObj, minMax, width, height) {
        if minMax = -1
            return
        this.layout.Resize(width, height)
    }

    HandleInputChanged(*) {
        SetTimer(this.statsTimer, 0)
        SetTimer(this.statsTimer, -90)
    }

    FlushStats() {
        this.UpdateStats()
    }

    ApplyCommand(name, *) {
        if !this.transforms.Has(name) {
            this.SetStatus("Unknown command: " name)
            return
        }
        oldText := this.Text
        newText := this.transforms[name].Call(oldText)
        if newText != oldText {
            this.history.Push(oldText)
            this.Text := newText
            A_Clipboard := newText
            this.SetStatus(name " applied and copied")
        } else {
            this.SetStatus(name " made no changes")
        }
        this.UpdateStats()
    }

    LoadClipboard(*) {
        text := ""
        try text := A_Clipboard
        catch Error as err {
            OutputDebug("Clipboard read failed: " err.Message)
            this.SetStatus("Clipboard text unavailable")
            return
        }
        this.Text := text
        this.SetStatus(text = "" ? "Clipboard empty" : "Clipboard loaded")
        this.UpdateStats()
    }

    CopyText(*) {
        A_Clipboard := this.Text
        this.SetStatus("Copied " StrLen(this.Text) " chars")
    }

    Undo(*) {
        if !this.history.HasAny {
            this.SetStatus("No undo history")
            return
        }
        this.Text := this.history.Pop()
        A_Clipboard := this.Text
        this.SetStatus("Undo restored and copied")
        this.UpdateStats()
    }

    ClearText(*) {
        if this.Text != ""
            this.history.Push(this.Text)
        this.Text := ""
        this.SetStatus("Cleared")
        this.UpdateStats()
    }

    UpdateStats() {
        text := this.Text
        this.controls["stats"].Text := StrLen(text) " chars | " TextTools.CountLines(text) " lines | undo " this.history.Count
    }

    SetStatus(text) {
        this.gui.Title := this.title " - " text
    }

    Text {
        get => this.controls["input"].Text
        set => this.controls["input"].Text := value
    }

    TrimLines(text) {
        lines := StrSplit(TextTools.NormalizeEol(text), "`n")
        out := []
        for line in lines
            out.Push(Trim(line))
        return TextTools.JoinLines(out, TextTools.EolOf(text))
    }

    DeduplicateLines(text) {
        lines := StrSplit(TextTools.NormalizeEol(text), "`n")
        seen := Map()
        out := []
        for line in lines {
            if seen.Has(line)
                continue
            seen[line] := true
            out.Push(line)
        }
        return TextTools.JoinLines(out, TextTools.EolOf(text))
    }

    SortLines(text) {
        lines := StrSplit(TextTools.NormalizeEol(text), "`n")
        sorted := ""
        for line in lines
            sorted .= line "`n"
        sorted := Sort(RTrim(sorted, "`n"), "C")
        return StrReplace(sorted, "`n", TextTools.EolOf(text))
    }

    ReverseLines(text) {
        lines := StrSplit(TextTools.NormalizeEol(text), "`n")
        out := []
        index := lines.Length
        while index >= 1 {
            out.Push(lines[index])
            index -= 1
        }
        return TextTools.JoinLines(out, TextTools.EolOf(text))
    }

    SnakeCase(text) {
        text := RegExReplace(TextTools.NormalizeEol(text), "\s+", " ")
        text := RegExReplace(Trim(text), "[^\pL\pN]+", "_")
        text := RegExReplace(text, "_+", "_")
        return StrLower(Trim(text, "_"))
    }
}


class DarkTheme {
    __New(guiObj) {
        this.gui := guiObj
        this.roles := Map()
        this.styles := Map()
        this.brushes := Map()
        this.buttons := Map()
        this.colorMessages := [0x0133, 0x0138]
        this.drawHwndOffset := A_PtrSize = 8 ? 24 : 20
        this.drawHdcOffset := A_PtrSize = 8 ? 32 : 24
        this.drawRectOffset := A_PtrSize = 8 ? 40 : 28
        this.Define("window", 0x202020, 0xE8E8E8)
        this.Define("edit", 0x181818, 0xF0F0F0)
        this.Define("surface", 0x202020, 0xE8E8E8)
        this.Define("panel", 0x1F1F1F, 0xE8E8E8)
        this.Define("status", 0x202020, 0xBDBDBD)
        this.Define("button", 0x2B2B2B, 0xFFFFFF)
        this.Define("buttonHot", 0x343434, 0xFFFFFF)
        this.Define("buttonDown", 0x242424, 0xFFFFFF)
        this.Define("buttonDisabled", 0x252525, 0x808080)
        this.Define("buttonFrame", 0xD6D6D6, 0xFFFFFF)
        this.Define("buttonFocusFrame", 0x73B8FF, 0xFFFFFF)
        this.gui.BackColor := this.Hex(this.styles["window"]["back"])
        this.colorHandler := this.HandleCtlColor.Bind(this)
        this.drawHandler := this.HandleDrawItem.Bind(this)
        for msg in this.colorMessages
            OnMessage(msg, this.colorHandler)
        OnMessage(0x002B, this.drawHandler)
    }

    Define(role, back, text) {
        style := Map()
        style["back"] := back
        style["text"] := text
        style["backref"] := this.ColorRef(back)
        style["textref"] := this.ColorRef(text)
        this.styles[role] := style
        this.brushes[role] := this.CreateBrush(back)
        return this
    }

    Register(control, role := "surface") {
        if role = "button" {
            this.buttons[control.Hwnd] := true
            control.Opt("+0x400B")
            return this
        }
        if !this.styles.Has(role)
            role := "surface"
        this.TrySetExplorerTheme(control.Hwnd)
        this.roles[control.Hwnd] := role
        style := this.styles[role]
        control.Opt("c" this.Hex(style["text"]))
        if role != "edit"
            control.Opt("Background" this.Hex(style["back"]))
        return this
    }

    HandleCtlColor(wParam, lParam, msg, hwnd) {
        if !this.roles.Has(lParam)
            return 0
        role := this.roles[lParam]
        style := this.styles[role]
        DllCall("gdi32\SetTextColor", "ptr", wParam, "uint", style["textref"])
        DllCall("gdi32\SetBkColor", "ptr", wParam, "uint", style["backref"])
        return this.brushes[role]
    }

    HandleDrawItem(wParam, lParam, msg, hwnd) {
        hwndItem := NumGet(lParam, this.drawHwndOffset, "ptr")
        if !this.buttons.Has(hwndItem)
            return 0
        itemState := NumGet(lParam, 16, "uint")
        hdc := NumGet(lParam, this.drawHdcOffset, "ptr")
        rectPtr := lParam + this.drawRectOffset
        backRole := "button"
        if itemState & 0x0004
            backRole := "buttonDisabled"
        else if itemState & 0x0001
            backRole := "buttonDown"
        else if itemState & 0x0040
            backRole := "buttonHot"
        style := this.styles[backRole]
        frameRole := itemState & 0x0010 ? "buttonFocusFrame" : "buttonFrame"
        font := DllCall("user32\SendMessageW", "ptr", hwndItem, "uint", 0x0031, "ptr", 0, "ptr", 0, "ptr")
        oldFont := font ? DllCall("gdi32\SelectObject", "ptr", hdc, "ptr", font, "ptr") : 0
        DllCall("user32\FillRect", "ptr", hdc, "ptr", rectPtr, "ptr", this.brushes[backRole])
        DllCall("user32\FrameRect", "ptr", hdc, "ptr", rectPtr, "ptr", this.brushes[frameRole])
        DllCall("gdi32\SetTextColor", "ptr", hdc, "uint", style["textref"])
        DllCall("gdi32\SetBkMode", "ptr", hdc, "int", 1)
        DllCall("user32\DrawTextW", "ptr", hdc, "str", this.GetWindowText(hwndItem), "int", -1, "ptr", rectPtr, "uint", 0x8825)
        if oldFont
            DllCall("gdi32\SelectObject", "ptr", hdc, "ptr", oldFont)
        return 1
    }

    GetWindowText(hwnd) {
        length := DllCall("user32\GetWindowTextLengthW", "ptr", hwnd, "int")
        buffer := Buffer((length + 1) * 2, 0)
        DllCall("user32\GetWindowTextW", "ptr", hwnd, "ptr", buffer.Ptr, "int", length + 1, "int")
        return StrGet(buffer.Ptr, "UTF-16")
    }

    ApplyWindowChrome() {
        try {
            enabled := 1
            result := DllCall("dwmapi\DwmSetWindowAttribute", "ptr", this.gui.Hwnd, "int", 20, "int*", enabled, "int", 4, "int")
            if result != 0
                DllCall("dwmapi\DwmSetWindowAttribute", "ptr", this.gui.Hwnd, "int", 19, "int*", enabled, "int", 4, "int")
        } catch Error as err {
            OutputDebug("DWM dark mode failed: " err.Message)
        }
        this.TrySetExplorerTheme(this.gui.Hwnd)
    }

    TrySetExplorerTheme(hwnd) {
        try DllCall("uxtheme\SetWindowTheme", "ptr", hwnd, "str", "DarkMode_Explorer", "ptr", 0)
        catch Error as err
            OutputDebug("Theme call failed: " err.Message)
    }

    CreateBrush(rgb) {
        return DllCall("gdi32\CreateSolidBrush", "uint", this.ColorRef(rgb), "ptr")
    }

    ColorRef(rgb) {
        r := (rgb >> 16) & 0xFF
        g := (rgb >> 8) & 0xFF
        b := rgb & 0xFF
        return (b << 16) | (g << 8) | r
    }

    Hex(rgb) {
        return Format("{:06X}", rgb)
    }

    Dispose() {
        for msg in this.colorMessages
            OnMessage(msg, this.colorHandler, 0)
        OnMessage(0x002B, this.drawHandler, 0)
        for role, brush in this.brushes {
            if brush
                DllCall("gdi32\DeleteObject", "ptr", brush)
        }
        this.brushes := Map()
    }
}

