class ControlWrapper {
    __New(guiObj, name, type, options, text := "") {
        this.gui := guiObj
        this.name := name
        this.type := type
        this.control := this.Create(type, options, text)
    }

    Create(type, options, text) {
        return this.gui.Add(type, options, text)
    }

    ApplyTheme(theme) {
        theme.Register(this.control, this.ThemeRole)
        return this
    }

    On(eventName, callback) {
        this.control.OnEvent(eventName, callback)
        return this
    }

    Move(x, y, w := "", h := "") {
        this.control.Move(x, y, w, h)
        return this
    }

    Focus() {
        this.control.Focus()
        return this
    }

    Enable() {
        this.control.Enabled := true
        return this
    }

    Disable() {
        this.control.Enabled := false
        return this
    }

    ThemeRole {
        get => "surface"
    }

    Text {
        get => this.control.Text
        set => this.control.Text := value
    }

    Enabled {
        get => this.control.Enabled
        set => this.control.Enabled := value
    }
}

