class PanelWrap extends ControlWrapper {
    __New(guiObj, name, options) {
        super.__New(guiObj, name, "Text", options " Border Background1F1F1F", "")
        this.children := Map()
    }

    AddChild(key, wrapper) {
        this.children[key] := wrapper
        return this
    }

    ApplyTheme(theme) {
        super.ApplyTheme(theme)
        for name, child in this.children
            child.ApplyTheme(theme)
        return this
    }

    ThemeRole {
        get => "panel"
    }

    __Enum(numberOfVars) {
        return this.children.__Enum(numberOfVars)
    }
