class CommandPanelWrap extends PanelWrap {
    __New(guiObj, name, options, registry) {
        this.registry := registry
        super.__New(guiObj, name, options)
        this.buttons := Map()
        this.callback := ""
        this.Build()
    }

    Build() {
        x := 662
        y := 126
        w := 120
        h := 30
        col := 0
        row := 0
        for name, transform in this.registry {
            opts := Format("x{} y{} w{} h{}", x + col * 132, y + row * 40, w, h)
            btn := ButtonWrap(this.gui, "cmd_" name, opts, name)
            btn.On("Click", this.HandleButton.Bind(this, name))
            this.buttons[name] := btn
            this.AddChild(name, btn)
            col += 1
            if col = 2 {
                col := 0
                row += 1
            }
        }
    }

    OnCommand(callback) {
        this.callback := callback
        return this
    }

    HandleButton(name, *) {
        if this.callback
            this.callback.Call(name)
    }

    Move(x, y, w := "", h := "") {
        super.Move(x, y, w, h)
        baseX := x + 12
        baseY := y + 24
        col := 0
        row := 0
        btnW := Max(90, Floor((w - 36) / 2))
        for name, btn in this.buttons {
            btn.Move(baseX + col * (btnW + 12), baseY + row * 40, btnW, 30)
            col += 1
            if col = 2 {
                col := 0
                row += 1
            }
        }
        return this
    }
}

class FlowLayout {
    __New(guiObj, controls) {
        this.gui := guiObj
        this.controls := controls
    }

    Resize(width, height) {
        left := 14
        top := 14
        gap := 14
        sideW := 270
        statusH := 28
        editW := Max(320, width - sideW - gap * 3)
        editH := Max(210, height - top * 3 - statusH)
        sideX := left + editW + gap
        this.controls["input"].Move(left, top, editW, editH)
        this.controls["stats"].Move(left, top + editH + 8, editW, statusH)
        this.controls["copy"].Move(sideX, top, 130, 32)
        this.controls["paste"].Move(sideX + 140, top, 130, 32)
        this.controls["undo"].Move(sideX, top + 40, 130, 32)
        this.controls["clear"].Move(sideX + 140, top + 40, 130, 32)
        this.controls["commands"].Move(sideX, top + 88, sideW, Max(120, height - top * 2 - 88))
    }
}

class TransformRegistry {
    __New() {
        this.items := Map()
        this.order := []
    }

    Add(name, transform) {
        if !this.items.Has(name)
            this.order.Push(name)
        this.items[name] := transform
        return this
    }

    Has(name) {
        return this.items.Has(name)
    }

    __Item[name] {
        get => this.items[name]
        set {
            if !this.items.Has(name)
                this.order.Push(name)
            this.items[name] := value
        }
    }

    __Enum(numberOfVars) {
        return OrderedRegistryEnum(this.order, this.items)
    }
}

class OrderedRegistryEnum {
    __New(order, items) {
        this.order := order
        this.items := items
        this.index := 0
    }

    Call(&name, &value := "") {
        this.index += 1
        if this.index > this.order.Length
            return false
        name := this.order[this.index]
        value := this.items[name]
        return true
    }
}

class TextTransform {
    __New(name, callback) {
        this.name := name
        this.callback := callback
    }

    Call(text) {
        return this.callback.Call(text)
    }
}

class TextHistory {
    __New(limit := 20) {
        this.limit := limit
        this.stack := []
    }

    Push(text) {
        if this.stack.Length && this.stack[this.stack.Length] = text
            return this
        this.stack.Push(text)
        while this.stack.Length > this.limit
            this.stack.RemoveAt(1)
        return this
    }

    Pop() {
        return this.stack.Pop()
    }

    Count {
        get => this.stack.Length
    }

    HasAny {
        get => this.stack.Length > 0
    }
}

class TextTools {
    static NormalizeEol(text) {
        text := StrReplace(text, "`r`n", "`n")
        return StrReplace(text, "`r", "`n")
    }

    static EolOf(text) {
        return InStr(text, "`r`n") ? "`r`n" : InStr(text, "`r") ? "`r" : "`n"
    }

    static CountLines(text) {
        if text = ""
            return 0
        normalized := TextTools.NormalizeEol(text)
        count := 1
        pos := 1
        while (pos := InStr(normalized, "`n", false, pos)) {
            count += 1
            pos += 1
        }
        return count
    }

    static JoinLines(lines, eol := "`n") {
        out := ""
        for index, line in lines
            out .= (index = 1 ? "" : eol) line
        return out
    }
}

