        local currentText
        currentText := this.EditBox.Text
        this.ApplyTransform(StrUpper(currentText))
    }

    HandleLower(ctrlObj, eventInfo) {
        local currentText
        currentText := this.EditBox.Text
        this.ApplyTransform(StrLower(currentText))
    }

    HandleFormat(ctrlObj, eventInfo) {
        local currentText, formattedText

        currentText := this.EditBox.Text
        if (currentText = "") {
            return
        }

        formattedText := StrReplace(currentText, A_Tab, "    ")
        formattedText := RegExReplace(formattedText, "m)[ `t]+$", "")
        formattedText := StrReplace(StrReplace(formattedText, "`r`n", "`n"), "`n", "`r`n")

        if (SubStr(formattedText, -2) != "`r`n") {
            formattedText .= "`r`n"
        }

        this.ApplyTransform(formattedText)
    }

    ApplyTransform(newTextStr) {
        this.EditBox.Text := newTextStr

        try {
            A_Clipboard := newTextStr
        } catch Error as err {
            OutputDebug("Clipboard write failed: " . err.Message)
        }

        this.UpdateMetrics()
    }

    HandleChange(ctrlObj, eventInfo) {
        this.UpdateMetrics()
    }

    UpdateMetrics() {
        local metricsMap
        metricsMap := this.EditBox.GetMetrics()
        this.StatusBar.UpdateStatus(metricsMap)
    }

    HandleResize(guiObj, minMaxState, guiWidth, guiHeight) {
        local margin, btnHeight, statHeight, editW, editH, btnY, btnW, statY

        if (minMaxState = -1) {
            return
