        margin := 10
        btnHeight := 35
        statHeight := 25

        editW := guiWidth - (margin * 2)
        editH := guiHeight - (margin * 4) - btnHeight - statHeight

        if (editW < 10 || editH < 10) {
            return
        }

        this.EditBox.Move(margin, margin, editW, editH)

        btnY := margin * 2 + editH
        btnW := (editW - (margin * 2)) / 3

        this.BtnUpper.Move(margin, btnY, btnW, btnHeight)
        this.BtnLower.Move(margin + btnW + margin, btnY, btnW, btnHeight)
        this.BtnFormat.Move(margin + (btnW * 2) + (margin * 2), btnY, btnW, btnHeight)

        statY := btnY + btnHeight + margin
        this.StatusBar.Move(margin, statY, editW, statHeight)
    }

    HandleClose(guiObj) {
        ExitApp()
    }
}

