        statusH := this.UiScale(22)

        usableW := width - (margin * 2)
        if usableW < this.UiScale(180)
            usableW := this.UiScale(180)

        btnW := Floor((usableW - (gap * 2)) / 3)
        if btnW < this.UiScale(90)
            btnW := this.UiScale(90)

        rowY := margin
        x1 := margin
        x2 := x1 + btnW + gap
        x3 := x2 + btnW + gap

        this.btnUpper.Move(x1, rowY, btnW, btnH)
        this.btnLower.Move(x2, rowY, btnW, btnH)
        this.btnFormat.Move(x3, rowY, btnW, btnH)

        editY := rowY + btnH + gap
        statusY := height - margin - statusH

        editH := statusY - gap - editY
        if editH < this.UiScale(80)
            editH := this.UiScale(80)

        this.edit.Move(margin, editY, usableW, editH)
        this.status.Move(margin, statusY, usableW, statusH)
    }

