        text := ""
        note := ""
        if ClipboardUtil.HasText() {
            text := ClipboardUtil.GetText()
            if text = ""
                note := "Clipboard text is empty."
        } else {
            note := "Clipboard has no text format."
        }

        this._suppressChange := true
        this.edit.Value := text
        this._suppressChange := false
        this.UpdateStatus(text, note)
    }

    ApplyTransform(kind) {
        text := this.edit.Value
        newText := ""

        if kind = "upper" {
            newText := StrUpper(text)
        } else if kind = "lower" {
            newText := StrLower(text)
        } else if kind = "format" {
            newText := TextUtil.Format(text)
        } else {
            return
        }

        this._suppressChange := true
        this.edit.Value := newText
        this._suppressChange := false

        ClipboardUtil.SetText(newText)
        this.UpdateStatus(newText, "Updated clipboard.")
    }

    OnUpper(*) {
        this.ApplyTransform("upper")
    }

    OnLower(*) {
        this.ApplyTransform("lower")
    }

    OnFormat(*) {
        this.ApplyTransform("format")
    }

    OnEditChange(ctrl, info) {
        if this._suppressChange
            return
        text := this.edit.Value
        this.UpdateStatus(text, "")
    }

    UpdateStatus(text, note) {
        stats := TextUtil.Stats(text)
        msg := "Chars: " stats["chars"] "   Lines: " stats["lines"]
        if note != ""
            msg .= "   |   " note
        this.status.Value := msg
    }

    OnGuiSize(guiObj, minMax, width, height) {
        if minMax = -1
            return
        this.Layout(width, height)
    }

