class TextUtil {
    static ToLf(text) {
        if text = ""
            return ""
        t := text
        t := StrReplace(t, "`r`n", "`n")
        t := StrReplace(t, "`r", "`n")
        return t
    }

    static ToCrLf(text) {
        if text = ""
            return ""
        t := TextUtil.ToLf(text)
        t := StrReplace(t, "`n", "`r`n")
        return t
    }

    static EndsWith(text, suffix) {
        if suffix = ""
            return true
        if StrLen(text) < StrLen(suffix)
            return false
        return SubStr(text, -StrLen(suffix)) = suffix
    }

    static Format(text) {
        lf := TextUtil.ToLf(text)
        if lf = ""
            return ""
        lines := StrSplit(lf, "`n")
        out := ""
        i := 0
        for _, line in lines {
            i += 1
            t := StrReplace(line, "`t", "    ")
            t := RegExReplace(t, "[ \t]+$")
            if i > 1
                out .= "`r`n"
            out .= t
        }
        if !TextUtil.EndsWith(out, "`r`n")
            out .= "`r`n"
        return out
    }

    static Stats(text) {
        stats := Map()
        stats["chars"] := StrLen(text)

        lf := TextUtil.ToLf(text)
        lf := RTrim(lf, "`n")
        if lf = "" {
            stats["lines"] := 0
            return stats
        }

        parts := StrSplit(lf, "`n")
        stats["lines"] := parts.Length
        return stats
    }
}

class ClipboardUtil {
    static HasText() {
        has := false
        if !DllCall("OpenClipboard", "Ptr", 0, "Int")
            return false
        try {
            hasUnicode := DllCall("IsClipboardFormatAvailable", "UInt", 13, "Int")
            hasAnsi := DllCall("IsClipboardFormatAvailable", "UInt", 1, "Int")
            has := (hasUnicode != 0) || (hasAnsi != 0)
        } finally {
            DllCall("CloseClipboard")
        }
        return has
    }

    static GetText() {
        text := ""
        try {
            text := A_Clipboard
        } catch as err {
            text := ""
            OutputDebug "ClipboardUtil.GetText error: " err.Message
        }
        return text
    }

    static SetText(text) {
        try {
            A_Clipboard := text
        } catch as err {
            OutputDebug "ClipboardUtil.SetText error: " err.Message
        }
    }
}

