        this.BtnRedo := ButtonWrap(this.Gui, "Button", "x340 y220 w50 h30 Background333333 cFFFFFF", "Redo")
        this.Status := TextWrap(this.Gui, "Text", "x10 y260 w380 h20 Background1E1E1E cAAAAAA", "Chars: 0 | Lines: 0")

        this.LoadClipboard()

        this.BtnUpper.OnEvent("Click", this.Transform.Bind(this, "Upper"))
        this.BtnLower.OnEvent("Click", this.Transform.Bind(this, "Lower"))
        this.BtnProper.OnEvent("Click", this.Transform.Bind(this, "Proper"))
        this.BtnUndo.OnEvent("Click", this.Undo.Bind(this))
        this.BtnRedo.OnEvent("Click", this.Redo.Bind(this))
        this.Edit.OnEvent("Change", this.OnEditChange.Bind(this))

        this.Gui.OnEvent("Size", this.OnSize.Bind(this))
        this.Gui.OnEvent("Close", this.Close.Bind(this))
        this.Gui.OnEvent("Escape", this.Close.Bind(this))

        Hotkey "^z", this.Undo.Bind(this)
        Hotkey "^y", this.Redo.Bind(this)

        this.UpdateHistoryButtons()
        this.Gui.Show("w400 h300")
    }

    LoadClipboard() {
        try {
            clipText := A_Clipboard
            if (clipText = "") {
                this.Edit.Value := "Clipboard is empty or contains non-text data."
            } else {
                this.Edit.Value := clipText
            }
        } catch as err {
            this.Edit.Value := "Failed to read clipboard: " err.Message
        }
        this.PushHistory(this.Edit.Value)
        this.UpdateStatus()
    }

    Transform(type, *) {
        currentText := this.Edit.Value
        if (currentText = "")
            return

        newText := ""
        if (type = "Upper")
            newText := StrUpper(currentText)
        else if (type = "Lower")
            newText := StrLower(currentText)
        else if (type = "Proper")
            newText := StrTitle(currentText)

        if (newText != currentText) {
            this.PushHistory(currentText)
            this.RedoStack := []
            this.IsUpdating := true
            this.Edit.Value := newText
            this.IsUpdating := false
            try {
                A_Clipboard := newText
            }
            this.UpdateHistoryButtons()
            this.UpdateStatus()
        }
    }

    PushHistory(text) {
        this.UndoStack.Push(text)
        if (this.UndoStack.Length > 50)
            this.UndoStack.RemoveAt(1)
    }

    Undo(*) {
        if (this.UndoStack.Length > 1) {
            current := this.UndoStack.Pop()
            this.RedoStack.Push(current)
            previous := this.UndoStack[this.UndoStack.Length]
            this.IsUpdating := true
            this.Edit.Value := previous
            this.IsUpdating := false
            try {
                A_Clipboard := previous
            }
            this.UpdateHistoryButtons()
            this.UpdateStatus()
        }
    }

    Redo(*) {
        if (this.RedoStack.Length > 0) {
            next := this.RedoStack.Pop()
            this.UndoStack.Push(next)
            this.IsUpdating := true
            this.Edit.Value := next
            this.IsUpdating := false
            try {
                A_Clipboard := next
            }
            this.UpdateHistoryButtons()
            this.UpdateStatus()
        }
    }

    OnEditChange(*) {
        if (!this.IsUpdating) {
            this.UpdateStatus()
            try {
                A_Clipboard := this.Edit.Value
            }
        }
    }

    UpdateHistoryButtons() {
        if (this.UndoStack.Length > 1)
            this.BtnUndo.Enable()
        else
            this.BtnUndo.Disable()

        if (this.RedoStack.Length > 0)
            this.BtnRedo.Enable()
        else
            this.BtnRedo.Disable()
    }

    UpdateStatus() {
        text := this.Edit.Value
        charCount := StrLen(text)
        lineCount := text = "" ? 0 : StrSplit(text, "`n").Length
        this.Status.Value := "Chars: " charCount " | Lines: " lineCount
    }

