class ClipboardEditor {
    static MARGIN := 10
    static BUTTON_WIDTH := 100
    static BUTTON_HEIGHT := 30
    static STATUS_HEIGHT := 25

    __New() {
        this.gui := Gui("+Resize +MinSize400x300", "Clipboard Editor")
        this.gui.OnEvent("Size", this.OnResize.Bind(this))
        this.gui.OnEvent("Close", this.OnClose.Bind(this))
        this.gui.OnEvent("Escape", this.OnClose.Bind(this))

        this.controls := Map()
        this.controls["edit"] := ""
        this.controls["btnUpper"] := ""
        this.controls["btnLower"] := ""
        this.controls["btnFormat"] := ""
        this.controls["status"] := ""

        this.CreateControls()
        this.LoadClipboard()
        this.UpdateStatus()
    }

    CreateControls() {
        margin := ClipboardEditor.MARGIN
        btnWidth := ClipboardEditor.BUTTON_WIDTH
        btnHeight := ClipboardEditor.BUTTON_HEIGHT
        statusHeight := ClipboardEditor.STATUS_HEIGHT

        this.controls["edit"] := EditWrap(this.gui, "x" margin " y" margin " W380 H200")
        this.controls["edit"].OnEvent("Change", this.OnEditChange.Bind(this))

        btnY := margin + 200 + margin

        this.controls["btnUpper"] := ButtonWrap(this.gui, "UPPERCASE", this.OnUpperClick.Bind(this), "x" margin " y" btnY " W" btnWidth " H" btnHeight)

        this.controls["btnLower"] := ButtonWrap(this.gui, "lowercase", this.OnLowerClick.Bind(this), "x+10 yp W" btnWidth " H" btnHeight)

        this.controls["btnFormat"] := ButtonWrap(this.gui, "Format", this.OnFormatClick.Bind(this), "x+10 yp W" btnWidth " H" btnHeight)

        statusY := btnY + btnHeight + margin
        this.controls["status"] := this.gui.Add("Text", "x" margin " y" statusY " W380 H" statusHeight, "Ready")
    }

    LoadClipboard() {
        try {
            clipText := A_Clipboard
            if (clipText = "") {
                this.controls["edit"].SetText("")
                this.SetStatus("Clipboard is empty")
            } else if !IsObject(clipText) {
                this.controls["edit"].SetText(clipText)
                this.SetStatus("Loaded from clipboard")
            } else {
                this.controls["edit"].SetText("")
                this.SetStatus("Clipboard contains non-text data")
            }
        } catch as err {
            this.controls["edit"].SetText("")
            this.SetStatus("Error reading clipboard: " err.Message)
        }
    }

    SaveToClipboard() {
        try {
            text := this.controls["edit"].GetText()
            A_Clipboard := text
            ClipWait(1)
            this.SetStatus("Saved to clipboard")
        } catch as err {
            this.SetStatus("Error saving to clipboard: " err.Message)
        }
    }

    UpdateStatus() {
        charCount := this.controls["edit"].GetCharCount()
        lineCount := this.controls["edit"].GetLineCount()
        this.SetStatus("Characters: " charCount " | Lines: " lineCount)
    }

    SetStatus(text) {
        this.controls["status"].Value := text
    }

    OnEditChange(*) {
        this.UpdateStatus()
    }

    OnUpperClick(*) {
        text := this.controls["edit"].GetText()
        this.controls["edit"].SetText(StrUpper(text))
        this.SaveToClipboard()
        this.UpdateStatus()
    }

    OnLowerClick(*) {
        text := this.controls["edit"].GetText()
        this.controls["edit"].SetText(StrLower(text))
        this.SaveToClipboard()
        this.UpdateStatus()
    }

    OnFormatClick(*) {
        text := this.controls["edit"].GetText()
        formatted := this.FormatText(text)
        this.controls["edit"].SetText(formatted)
        this.SaveToClipboard()
        this.UpdateStatus()
    }

    FormatText(text) {
        text := StrReplace(text, "`r`n", "`n")
        text := StrReplace(text, "`r", "`n")

        lines := StrSplit(text, "`n")
        result := ""

        for index, line in lines {
            line := RTrim(line)
            line := StrReplace(line, "`t", "    ")
            result .= line
            if (index < lines.Length)
                result .= "`r`n"
        }

        if (result != "" && !InStr(result, "`r`n", , -1))
            result .= "`r`n"

        return result
    }

    OnResize(thisGui, minMax, width, height) {
        if (minMax = -1)
            return

        margin := ClipboardEditor.MARGIN
        btnWidth := ClipboardEditor.BUTTON_WIDTH
        btnHeight := ClipboardEditor.BUTTON_HEIGHT
        statusHeight := ClipboardEditor.STATUS_HEIGHT

        editWidth := width - (margin * 2)
        editHeight := height - (margin * 4) - btnHeight - statusHeight

        this.controls["edit"].Move(margin, margin, editWidth, editHeight)

        btnY := margin + editHeight + margin

        this.controls["btnUpper"].Move(margin, btnY, btnWidth, btnHeight)
        this.controls["btnLower"].Move(margin + btnWidth + 10, btnY, btnWidth, btnHeight)
        this.controls["btnFormat"].Move(margin + (btnWidth + 10) * 2, btnY, btnWidth, btnHeight)

        statusY := btnY + btnHeight + margin
        this.controls["status"].Move(margin, statusY, editWidth, statusHeight)
    }

    OnClose(*) {
        this.gui.Destroy()
        ExitApp()
    }

    Show() {
        this.gui.Show("W500 H400")
    }
}

