    __New() {
        this.history := []
        this.redoStack := []
        this.gui := Gui("+Resize", "Clipboard Formatter")
        this.gui.OnEvent("Size", this.OnSize.Bind(this))
        this.gui.OnEvent("Escape", this.OnEscape.Bind(this))
        this.gui.SetFont("s10", "Segoe UI")
        this.gui.BackColor := "0x1E1E1E"
        this.gui.MarginX := 10
        this.gui.MarginY := 10

        ; Edit control via EditWrap
        this.edit := EditWrap(this.gui, "Edit", "r20 w500 +Multi", "")
        this.edit.guiObj.OnEvent("Change", this.OnEditChange.Bind(this))

        ; Buttons via ButtonWrap
        this.btnUpper := ButtonWrap(this.gui, "Button", "w120", "UPPER CASE")
        this.btnUpper.guiObj.OnEvent("Click", this.OnUpper.Bind(this))
        this.btnLower := ButtonWrap(this.gui, "Button", "w120", "lower case")
        this.btnLower.guiObj.OnEvent("Click", this.OnLower.Bind(this))
        this.btnProper := ButtonWrap(this.gui, "Button", "w120", "Proper Case")
        this.btnProper.guiObj.OnEvent("Click", this.OnProper.Bind(this))
        this.btnUndo := ButtonWrap(this.gui, "Button", "w120", "Undo (Ctrl+Z)")
        this.btnUndo.guiObj.OnEvent("Click", this.OnUndo.Bind(this))
        this.btnRedo := ButtonWrap(this.gui, "Button", "w120", "Redo (Ctrl+Y)")
        this.btnRedo.guiObj.OnEvent("Click", this.OnRedo.Bind(this))

        ; Status text
        this.status := this.gui.Add("Text", "w500", "Characters: 0 | Lines: 0")

        this.gui.Show()
        this.LoadClipboard()
        this.UpdateStatus()
        this.UpdateButtonStates()
    }

    LoadClipboard() {
        try {
            clipText := ClipboardAll()
            if !IsObject(clipText) && clipText != "" {
                this.edit.Update(clipText)
                this.history.Push(clipText)
            } else {
                this.edit.Update("")
                this.history.Push("")
            }
        } catch {
            this.edit.Update("")
            this.history.Push("")
        }
    }

    OnUpper(*) {
        this.TransformText(StrUpper)
    }

    OnLower(*) {
        this.TransformText(StrLower)
    }

    OnProper(*) {
        this.TransformText(StrTitle)
    }

    TransformText(func) {
        current := this.edit.GetText()
        transformed := func(current)
        this.edit.Update(transformed)
        A_Clipboard := transformed
        this.history.Push(transformed)
        this.redoStack.Clear()
        this.UpdateStatus()
        this.UpdateButtonStates()
    }

    OnUndo(*) {
        if this.history.Length > 1 {
            this.redoStack.Push(this.history.Pop())
            previous := this.history[this.history.Length]
            this.edit.Update(previous)
            A_Clipboard := previous
            this.UpdateStatus()
            this.UpdateButtonStates()
        }
    }

    OnRedo(*) {
        if this.redoStack.Length > 0 {
            next := this.redoStack.Pop()
            this.edit.Update(next)
            this.history.Push(next)
            A_Clipboard := next
            this.UpdateStatus()
            this.UpdateButtonStates()
        }
    }

    OnEditChange(*) {
        this.UpdateStatus()
    }

    UpdateStatus() {
        text := this.edit.GetText()
        charCount := StrLen(text)
        lineCount := StrSplit(text, "`n").Length
        this.status.Value := "Characters: " charCount " | Lines: " lineCount
    }

    UpdateButtonStates() {
        this.btnUndo.Update(this.history.Length > 1)
        this.btnRedo.Update(this.redoStack.Length > 0)
    }

    OnSize(guiObj, minMax, width, height) {
        if minMax == -1
            return
        this.edit.guiObj.Move( , , width - 20)
        this.status.Move( , , width - 20)
    }

    OnEscape(*) {
        this.gui.Destroy()
    }

    __Delete() {
        if this.gui
            this.gui.Destroy()
    }
}

