class Util {
    static Wrap(v, lo, hi) {
        n := hi - lo + 1
        return Mod(Mod(v - lo, n) + n, n) + lo
    }
    static SortBy(arr, keyFn) {
        i := 2
        while i <= arr.Length {
            j := i
            while j > 1 && keyFn(arr[j - 1]) > keyFn(arr[j]) {
                tmp := arr[j - 1]
                arr[j - 1] := arr[j]
                arr[j] := tmp
                j--
            }
            i++
        }
        return arr
    }
}

class Calc {
    static Eval(expr) {
        tokens := Calc.Tokenize(expr)
        pos := 1
        value := Calc.ParseExpr(tokens, &pos)
        if pos <= tokens.Length
            throw Error("Unexpected token at " pos)
        return value
    }
    static Tokenize(expr) {
        tokens := []
        i := 1
        while i <= StrLen(expr) {
            ch := SubStr(expr, i, 1)
            if ch = " " {
                i++
            } else if InStr("+-*/()^%", ch) {
                tokens.Push(ch)
                i++
            } else if RegExMatch(SubStr(expr, i), "^\d+(\.\d+)?", &m) {
                tokens.Push(m[0] + 0)
                i += StrLen(m[0])
            } else {
                throw Error("Invalid character: " ch)
            }
        }
        return tokens
    }
    static ParseExpr(t, &p) {
        v := Calc.ParseTerm(t, &p)
        while p <= t.Length && (t[p] = "+" || t[p] = "-") {
            op := t[p]
            p++
            r := Calc.ParseTerm(t, &p)
            v := op = "+" ? v + r : v - r
        }
        return v
    }
    static ParseTerm(t, &p) {
        v := Calc.ParseFactor(t, &p)
        while p <= t.Length && (t[p] = "*" || t[p] = "/" || t[p] = "%") {
            op := t[p]
            p++
            r := Calc.ParseFactor(t, &p)
            if (op = "/" || op = "%") && r = 0
                throw Error("Division by zero")
            v := op = "*" ? v * r : op = "/" ? v / r : Mod(v, r)
        }
        return v
    }
    static ParseFactor(t, &p) {
        if p <= t.Length && t[p] = "-" {
            p++
            return -Calc.ParseFactor(t, &p)
        }
        if p <= t.Length && t[p] = "(" {
            p++
            v := Calc.ParseExpr(t, &p)
            if p > t.Length || t[p] != ")"
                throw Error("Missing closing parenthesis")
            p++
            return Calc.ParsePow(t, &p, v)
        }
        if p <= t.Length && IsNumber(t[p]) {
            v := t[p]
            p++
            return Calc.ParsePow(t, &p, v)
        }
        throw Error("Expected a value")
    }
    static ParsePow(t, &p, base) {
        if p <= t.Length && t[p] = "^" {
            p++
            return base ** Calc.ParseFactor(t, &p)
        }
        return base
    }
}

