class QueryEngine {
    __New(registry) {
        this.registry := registry
        this.providers := []
    }
    AddProvider(fn) => this.providers.Push(fn)
    Search(query, group) {
        results := []
        for provider in this.providers
            for cmd in provider(query)
                results.Push(cmd)
        if query != ""
            for cmd in this.registry.All()
                if InStr(cmd.Haystack(), query, false)
                    results.Push(cmd)
        if group
            Util.SortBy(results, (c) => c.Category)
        return results
    }
