class Knowledge {
    static Units := Map(
        "kg", Map("to", "lb", "f", 2.2046226),
        "lb", Map("to", "kg", "f", 0.45359237),
        "km", Map("to", "mi", "f", 0.62137119),
        "mi", Map("to", "km", "f", 1.609344)
    )
    static CalcProvider(query) {
        results := []
        if !RegExMatch(query, "^[\d\s\.\+\-\*/\(\)\^%]+$") || !RegExMatch(query, "\d") || !RegExMatch(query, "[\+\*/\^%]|\d\s*-")
            return results
        try {
            value := Calc.Eval(query)
        } catch as err {
            OutputDebug(err.Message)
            return results
        }
        pretty := Format("{:g}", value)
        results.Push(Command("kn-calc", "= " pretty,
            (ctx) => ctx.Palette.CopyResult(pretty),
            Map("Subtitle", query " — Enter to copy", "IconKey", "calc", "Category", "Knowledge")))
        return results
    }
    static ConvertProvider(query) {
        results := []
        if !RegExMatch(query, "i)^\s*(-?\d+(?:\.\d+)?)\s*(kg|lb|km|mi|c|f)\s*$", &m)
            return results
        value := m[1] + 0
        unit := StrLower(m[2])
        if unit = "c"
            pretty := Format("{:.2f} °F", value * 9 / 5 + 32)
        else if unit = "f"
            pretty := Format("{:.2f} °C", (value - 32) * 5 / 9)
        else {
            info := Knowledge.Units[unit]
            pretty := Format("{:.6g} {}", value * info["f"], info["to"])
        }
        results.Push(Command("kn-convert", value " " unit " = " pretty,
            (ctx) => ctx.Palette.CopyResult(pretty),
            Map("Subtitle", "Local conversion — Enter to copy", "IconKey", "convert", "Category", "Knowledge")))
        return results
    }
}

