        .Add(TextCommands.Make("txt-reverse", "Reverse Selected Lines", "sort", (t) => TextCommands.SortLines(t, " R"), ["flip", "order"]))
        .Add(TextCommands.Make("txt-quote", "Wrap Selection in Quotes", "wrap", (t) => '"' t '"', ["surround", "string"]))
        .Add(TextCommands.Make("txt-bracket", "Wrap Selection in Brackets", "wrap", (t) => "[" t "]", ["surround", "array"]))
        .Add(Command("txt-replace", "Find / Replace…",
            (ctx) => TextCommands.FindReplace(ctx, false),
            Map("Subtitle", "Prompted replace in selection or all text", "IconKey", "find", "Category", "Text", "Keywords", ["substitute", "search"])))
        .Add(Command("txt-regex", "Regex Replace…",
            (ctx) => TextCommands.FindReplace(ctx, true),
            Map("Subtitle", "Prompted RegExReplace", "IconKey", "find", "Category", "Text", "Keywords", ["pattern", "pcre"])))
    }
    static Make(id, title, iconKey, fn, keywords) {
        return Command(id, title,
            (ctx) => TextCommands.Apply(ctx, fn),
            Map("Subtitle", "Transforms the current selection", "IconKey", iconKey, "Category", "Text", "Keywords", keywords))
    }
    static Apply(ctx, fn) {
        if ctx.Adapter = ""
            return ctx.Palette.Toast("No editor attached")
        sel := ctx.Adapter.GetSelectionText()
        if sel = ""
            return ctx.Palette.Toast("No text selected")
        ctx.Adapter.ReplaceSelectionText(fn(sel))
    }
    static SortLines(text, opts) {
        return Sort(text, "D`n" opts)
    }
    static FindReplace(ctx, useRegex) {
        if ctx.Adapter = ""
            return ctx.Palette.Toast("No editor attached")
        f := InputBox(useRegex ? "Regex pattern:" : "Find:", "Find / Replace")
        if f.Result != "OK" || f.Value = ""
            return
        r := InputBox("Replace with:", "Find / Replace")
        if r.Result != "OK"
            return
        hasSel := ctx.Adapter.HasSelection()
        src := hasSel ? ctx.Adapter.GetSelectionText() : ctx.Adapter.GetAllText()
        out := useRegex ? RegExReplace(src, f.Value, r.Value) : StrReplace(src, f.Value, r.Value)
        hasSel ? ctx.Adapter.ReplaceSelectionText(out) : ctx.Adapter.SetAllText(out)
    }
}

