    static RowH := 46
    static StatusH := 30

    __New(config := unset) {
        this.cfg := IsSet(config) ? config : Map()
        this.w := this.cfg.Get("Width", 620)
        this.maxRows := this.cfg.Get("MaxRows", 7)
        this.grouping := false
        this.adapter := ""
        this.matches := []
        this.sel := 0
        this.Registry := CommandRegistry()
        this.engine := QueryEngine(this.Registry)
        this.engine.AddProvider((q) => Knowledge.CalcProvider(q))
        this.engine.AddProvider((q) => Knowledge.ConvertProvider(q))
        this.BuildGui()
        this.BindKeys()
        Hotkey(this.cfg.Get("Hotkey", "^k"), this.Toggle.Bind(this))
        OnMessage(0x0006, this.boundActivate := this.OnActivate.Bind(this))
    }

    SetAdapter(adapter) => this.adapter := adapter
    ToggleGrouping() => this.Toast("Category grouping " ((this.grouping := !this.grouping) ? "on" : "off"))
    CopyResult(value) {
        A_Clipboard := value
        this.Toast("Copied: " value)
    }

    BuildGui() {
        this.gui := Gui("-Caption +AlwaysOnTop +ToolWindow", "CommandPalette")
        this.gui.BackColor := Theme.WinBg
        this.gui.MarginX := 0
        this.gui.MarginY := 0
        this.gui.SetFont("s11 c" Theme.TextMain, "Segoe UI")
        this.gui.SetFont("s13")
        this.gui.AddText("x16 y13 w28 h28 +0x200 Background" Theme.WinBg, "🔍")
        this.gui.SetFont("s12")
        this.input := this.gui.AddEdit("x50 y12 w" (this.w - 66) " h28 -E0x200 Background" Theme.InputBg " c" Theme.TextMain)
        this.input.OnEvent("Change", this.OnQueryChanged.Bind(this))
        DllCall("uxtheme\SetWindowTheme", "ptr", this.input.Hwnd, "str", "DarkMode_Explorer", "ptr", 0)
        this.gui.SetFont("s11")
        this.rows := []
        y := CommandPalette.SearchH
        Loop this.maxRows {
            this.rows.Push(PaletteRow(this, y, A_Index))
            y += CommandPalette.RowH
        }
        this.gui.SetFont("s9")
        this.status := this.gui.AddText("x16 y" CommandPalette.SearchH " w" (this.w - 32) " h18 c" Theme.TextDim " Background" Theme.WinBg, "Type to search commands")
        this.gui.SetFont("s11")
        DllCall("dwmapi\DwmSetWindowAttribute", "ptr", this.gui.Hwnd, "int", 20, "int*", true, "int", 4)
        DllCall("dwmapi\DwmSetWindowAttribute", "ptr", this.gui.Hwnd, "int", 33, "int*", 2, "int", 4)
    }

    BindKeys() {
        HotIfWinActive("ahk_id " this.gui.Hwnd)
        Hotkey("Up", this.OnNav.Bind(this, -1))
        Hotkey("Down", this.OnNav.Bind(this, 1))
        Hotkey("Enter", this.OnEnter.Bind(this))
        Hotkey("NumpadEnter", this.OnEnter.Bind(this))
        Hotkey("Escape", this.OnEscape.Bind(this))
        HotIfWinActive()
    }

    Toggle(*) => DllCall("IsWindowVisible", "ptr", this.gui.Hwnd) ? this.Hide() : this.Show()

    Show() {
        this.input.Value := ""
        this.Refresh()
        x := (A_ScreenWidth - this.w) // 2
        y := Round(A_ScreenHeight * 0.18)
        this.gui.Show("x" x " y" y " w" this.w " h" this.Height())
        this.input.Focus()
    }

    Hide() => this.gui.Hide()
    Height() => CommandPalette.SearchH + this.matches.Length * CommandPalette.RowH + CommandPalette.StatusH

    Refresh() {
        query := Trim(this.input.Value)
        this.matches := this.engine.Search(query, this.grouping)
        if this.matches.Length > this.maxRows
            this.matches.Length := this.maxRows
        this.sel := this.matches.Length ? 1 : 0
        this.Render()
    }

    Render() {
        for i, row in this.rows {
            if i <= this.matches.Length
                row.Set(this.matches[i], i = this.sel)
            else
                row.Hide()
        }
        this.status.Move(16, CommandPalette.SearchH + this.matches.Length * CommandPalette.RowH + 6)
        this.gui.Move(, , this.w, this.Height())
    }

    SetStatus(msg) {
        this.status.Value := msg
        SetTimer((*) => this.status.Value := "", -2500)
    }

    Toast(msg) {
        ToolTip(msg, A_ScreenWidth // 2, Round(A_ScreenHeight * 0.12))
        SetTimer((*) => ToolTip(), -1600)
    }

    OnQueryChanged(*) => this.Refresh()

    OnNav(delta, *) {
        if !this.matches.Length
            return
        this.sel := Util.Wrap(this.sel + delta, 1, this.matches.Length)
        this.Render()
    }

    OnEnter(*) {
        if this.sel
            this.Execute(this.matches[this.sel])
    }

    OnEscape(*) => this.Hide()

    OnRowClick(index) {
        if index <= this.matches.Length {
            this.sel := index
            this.Execute(this.matches[index])
        }
    }

    OnActivate(wParam, lParam, msg, hwnd) {
        if hwnd = this.gui.Hwnd && (wParam & 0xFFFF) = 0
            this.Hide()
    }

    Execute(cmd) {
        this.SetStatus("Running " cmd.Title "…")
        ctx := Context(this, this.adapter, Trim(this.input.Value))
        this.Hide()
        try {
            cmd.Run(ctx)
            this.Toast("✓ " cmd.Title)
        } catch as err {
            OutputDebug(err.Message)
            this.Toast("✗ " cmd.Title ": " err.Message)
        }
    }
}

