class ClipboardBridge {
    static Read() => A_Clipboard
    static Write(text) {
        A_Clipboard := text
    }
}

class TextTransform {
    static Upper(text) => StrUpper(text)
    static Lower(text) => StrLower(text)
    static Format(text) {
        text := StrReplace(text, "`r`n", "`n")
        text := StrReplace(text, "`r", "`n")
        text := StrReplace(text, "`t", "    ")
        out := ""
        for line in StrSplit(text, "`n") {
            out .= RTrim(line, " `t") . "`r`n"
        }
        while SubStr(out, -4) = "`r`n`r`n" {
            out := SubStr(out, 1, -2)
        }
        if out = "" {
            out := "`r`n"
        } else if SubStr(out, -2) != "`r`n" {
            out .= "`r`n"
        }
        return out
    }
}

