class ClipboardEditor {
    static Pad := 12
    static BtnW := 116
    static BtnH := 34
    static BtnGap := 10
    static StatusH := 22
    static InitW := 560
    static InitH := 400

    __New() {
        this.actions := Map()
        this._buttons := Map()
        this._writing := false

        this.gui := Gui("+Resize +MinSize460x320", "Clipboard Editor")
        this.gui.BackColor := 0x1E1E1E
        this.gui.MarginX := ClipboardEditor.Pad
        this.gui.MarginY := ClipboardEditor.Pad

        this.gui.SetFont("s11 cE6E6E6", "Consolas")
        this.edit := EditWrap(this.gui,
            "xm ym w536 h260 Multi WantReturn WantTab VScroll Background252526", "")
        this.edit.Bind("Change", this._onEdit.Bind(this))

        this.gui.SetFont("s9 cB8B8B8", "Segoe UI")
        this.status := this.gui.Add("Text",
            "xm w536 h22 Background1E1E1E", "")

        this.gui.SetFont("s10 cFFFFFF", "Segoe UI Semibold")
        this._registerAction("UPPERCASE", TextTransform.Upper)
        this._registerAction("lowercase", TextTransform.Lower)
        this._registerAction("Format",    TextTransform.Format)

        this.gui.OnEvent("Size",   this._onResize.Bind(this))
        this.gui.OnEvent("Close",  (*) => (ExitApp(), 0))
        this.gui.OnEvent("Escape", (*) => (ExitApp(), 0))

        this.edit.Ctrl.Value := ClipboardBridge.Read()
        this._refreshStatus()

        this.gui.Show("w" . ClipboardEditor.InitW . " h" . ClipboardEditor.InitH)
    }

    _registerAction(name, transform) {
        this.actions[name] := transform
        idx := this._buttons.Count
        x := ClipboardEditor.Pad + idx * (ClipboardEditor.BtnW + ClipboardEditor.BtnGap)
        opts := "x" . x . " y306 w" . ClipboardEditor.BtnW
              . " h" . ClipboardEditor.BtnH . " Background3C3C3C"
        btn := ButtonWrap(this.gui, opts, name)
        btn.OnClick(this._invoke.Bind(this, name))
        this._buttons[name] := btn
    }

    _invoke(name, *) {
        if !this.actions.Has(name) {
            return
        }
        transform := this.actions[name]
        this._writing := true
        result := transform(this.edit.Ctrl.Value)
        this.edit.Value := result
        ClipboardBridge.Write(result)
        this._writing := false
        this._refreshStatus()
    }

    _onEdit(*) {
        if this._writing {
            return
        }
        ClipboardBridge.Write(this.edit.Ctrl.Value)
        this._refreshStatus()
    }

    _refreshStatus() {
        s := this.edit.Stats
        this.status.Value := "  Chars: " . s["chars"] . "      Lines: " . s["lines"]
    }

    _onResize(guiObj, minMax, w, h) {
        if minMax = -1 {
            return
        }
        pad     := ClipboardEditor.Pad
        btnH    := ClipboardEditor.BtnH
        btnW    := ClipboardEditor.BtnW
        gap     := ClipboardEditor.BtnGap
        statusH := ClipboardEditor.StatusH

        contentW := w - pad * 2
        if contentW < 200 {
            contentW := 200
        }
        editH := h - pad * 4 - statusH - btnH
        if editH < 80 {
            editH := 80
        }

        this.edit.Move(pad, pad, contentW, editH)
        statusY := pad + editH + pad
        this.status.Move(pad, statusY, contentW, statusH)
        btnY := statusY + statusH + pad
        x := pad
        for _, btn in this._buttons {
            btn.Move(x, btnY, btnW, btnH)
            x += btnW + gap
        }
    }
}

