    }

    LoadClipboard() {
        text := ""
        try {
            text := A_Clipboard
        } catch as err {
            this.Notify("Could not read the clipboard: " err.Message
                . "`nStarting with empty text.")
            text := ""
        }
        if (text = "") {
            this.edit.SetText("")
            this.SetStatusNote("Clipboard is empty or holds no text. "
                . "Type or paste, then transform.")
            return
        }
        this.edit.SetText(text)
    }

    PushHistory(oldText) {
        this.history.Push(oldText)
        this.future := []
        this.UpdateHistoryButtons()
    }

    ApplyTransform(transformFn) {
        current := this.edit.GetText()
        if (current = "") {
            this.Notify("There is no text to transform. "
                . "Type or paste text first.")
            return
        }
        result := transformFn(current)
        if (result = current) {
            this.SetStatusNote("No change: text is already in that form.")
            return
        }
        this.PushHistory(current)
        this.edit.SetText(result)
        this.WriteClipboard(result)
        this.RefreshStatus()
    }

    OnUpper(*) {
        this.ApplyTransform(StrUpper)
    }

    OnLower(*) {
        this.ApplyTransform(StrLower)
    }

    OnProper(*) {
        this.ApplyTransform(StrTitle)
    }

    OnUndo(*) {
        if (this.history.Length = 0) {
            this.SetStatusNote("Nothing to undo.")
            return
        }
        current := this.edit.GetText()
        previous := this.history.Pop()
        this.future.Push(current)
        this.edit.SetText(previous)
        this.WriteClipboard(previous)
        this.UpdateHistoryButtons()
        this.RefreshStatus()
    }

    OnRedo(*) {
        if (this.future.Length = 0) {
            this.SetStatusNote("Nothing to redo.")
            return
        }
        current := this.edit.GetText()
        next := this.future.Pop()
        this.history.Push(current)
        this.edit.SetText(next)
        this.WriteClipboard(next)
        this.UpdateHistoryButtons()
        this.RefreshStatus()
    }

    OnEditChange(*) {
        this.RefreshStatus()
    }

    WriteClipboard(text) {
        try {
            A_Clipboard := text
        } catch as err {
            this.Notify("Could not write to the clipboard: " err.Message)
        }
    }

    UpdateHistoryButtons() {
        this.btnUndo.SetEnabled(this.history.Length > 0)
        this.btnRedo.SetEnabled(this.future.Length > 0)
    }

    CountLines(text) {
        if (text = "")
            return 0
        count := 1
        loop parse text, "`n", "`r"
            count := A_Index
        return count
    }

    RefreshStatus() {
        text := this.edit.GetText()
        chars := StrLen(text)
        lines := this.CountLines(text)
        this.status.Value := "Chars: " chars "    Lines: " lines
            . "    Undo: " this.history.Length
            . "    Redo: " this.future.Length
    }

    SetStatusNote(note) {
        this.status.Value := note
    }

    Notify(message) {
        MsgBox(message, "Clipboard Text Formatter", "Iconi 4096")
    }

    OnSize(guiObj, minMax, width, height) {
        if (minMax = -1)
            return
        this.edit.Anchor(width, height)
        this.btnUpper.Anchor(width, height)
        this.btnLower.Anchor(width, height)
        this.btnProper.Anchor(width, height)
        this.btnUndo.Anchor(width, height)
        this.btnRedo.Anchor(width, height)
        this.status.Move(this.margin, height - this.statusRow,
            width - (this.margin * 2))
    }

    OnEscape(*) {
        this.gui.Destroy()
        ExitApp()
    }

    __Delete() {
        try {
            HotIfWinActive("ahk_id " this.gui.Hwnd)
            Hotkey("^z", "Off")
            Hotkey("^y", "Off")
            HotIf()
        } catch as err {
            OutputDebug("Hotkey cleanup skipped: " err.Message)
        }
    }
}

