        current := this.editControl.Value
        newText := transformFn(current)
        this.editControl.Value := newText
        A_Clipboard := newText
        this.UpdateStatus()
    }

    FormatText(text) {
        text := StrReplace(text, "`r`n", "`n")
        text := StrReplace(text, "`r", "`n")
        lines := StrSplit(text, "`n")
        newLines := []
        for line in lines {
            line := RTrim(line)
            line := StrReplace(line, "`t", "    ")
            newLines.Push(line)
        }
        result := ""
        for i, line in newLines {
            result .= line
            if i < newLines.Length {
                result .= "`r`n"
            }
        }
        if SubStr(result, -1) != "`r`n" {
            result .= "`r`n"
        }
        return result
    }

    UpdateStatus(*) {
        text := this.editControl.Value
        charCount := StrLen(text)
        if text = "" {
            lineCount := 0
        } else {
            lineCount := StrSplit(text, "`n", "`r").Length
        }
        this.statusText.Text := "Characters: " . charCount . " | Lines: " . lineCount
    }

