class Transformer {
    static ToUpper(str) => StrUpper(str)
    static ToLower(str) => StrLower(str)
    static Format(str) {
        text := StrReplace(str, "`t", "    ")
        lines := StrSplit(text, "`n", "`r")
        newLines := []
        for line in lines {
            newLines.Push(RTrim(line, " `t"))
        }
        return Trim(Join(newLines, "`r`n"), "`r`n") . "`r`n"
    }
}

Join(arr, sep) {
    res := ""
    for v in arr
        res .= (A_Index > 1 ? sep : "") . v
    return res
}

