        result    := ""
        capNext   := true
        loop Parse, txt {
            ch := A_LoopField
            if (ch = " " or ch = "`n" or ch = "`r" or ch = "`t") {
                result  .= ch
                capNext := true
            } else if (capNext) {
                result  .= StrUpper(ch)
                capNext := false
            } else {
                result .= StrLower(ch)
            }
        }
        return result
    }

