class CommandPalette
{
    __New(adapter := "")
    {
        this.Adapter := adapter
        this.Commands := Map()
        this.FilteredCommands := Array()
        this.GUI := Gui("-Caption +AlwaysOnTop +ToolWindow")
        this.GUI.BackColor := "1E1E1E"
