        this.SearchEdit := this.GUI.Add("Edit", "x12 y12 w376 h36 Background2D2D2D -Border", "")
        this.SearchEdit.OnEvent("Change", this.OnSearchChange.Bind(this))
        this.ResultsList := this.GUI.Add("ListView", "x12 y58 w376 h0 -Hdr -Multi AltSubmit Background333333 cFFFFFF", ["", "Title", "Subtitle"])
        this.ResultsList.OnEvent("DoubleClick", this.OnExecute.Bind(this))
        this.ResultsList.ModifyCol(1, 32)
        this.ResultsList.ModifyCol(2, 240)
        this.ResultsList.ModifyCol(3, 100)
        this.GUI.OnMessage(0x100, this.WM_KEYDOWN.Bind(this))
        this.GUI.OnEvent("Escape", this.Hide.Bind(this))
        this.RegisterDefaultCommands()
        this.GUI.Show("Hide")
    }

    RegisterDefaultCommands()
    {
        this.Commands["trim"] := Command("trim", "Trim Selection", "Remove whitespace from selection", Array("trim", "clean"), "Text", this.DoTrim.Bind(this))
        this.Commands["upper"] := Command("upper", "Upper Case", "Convert selection to uppercase", Array("upper", "case"), "Text", this.DoUpper.Bind(this))
        this.Commands["lower"] := Command("lower", "Lower Case", "Convert selection to lowercase", Array("lower", "case"), "Text", this.DoLower.Bind(this))
        this.Commands["title"] := Command("title", "Title Case", "Convert selection to Title Case", Array("title", "case"), "Text", this.DoTitle.Bind(this))
        this.Commands["sort"] := Command("sort", "Sort Lines", "Sort selected lines alphabetically", Array("sort", "lines"), "Text", this.DoSort.Bind(this))
        this.Commands["reverse"] := Command("reverse", "Reverse Lines", "Reverse order of selected lines", Array("reverse", "lines"), "Text", this.DoReverse.Bind(this))
        this.Commands["calc"] := Command("calc", "Calculator", "Evaluate basic math expression", Array("calc", "math"), "Knowledge", this.DoCalculator.Bind(this))
    }

    OnSearchChange(*)
    {
        local query := Trim(this.SearchEdit.Value)
        this.FilteredCommands := Array()
        if (query != "")
        {
            for , cmd in this.Commands
            {
                if (this.CommandMatches(cmd, query))
                    this.FilteredCommands.Push(cmd)
            }
            local calcResult := this.TryCalculate(query)
            if (calcResult != "")
            {
                local dynCmd := Command("dyncalc", query " = " calcResult, "Quick calculation", Array(), "Knowledge", this.DoCalculator.Bind(this))
                this.FilteredCommands.InsertAt(1, dynCmd)
            }
        }
        else
        {
            for , cmd in this.Commands
                this.FilteredCommands.Push(cmd)
        }
        this.UpdateListView()
    }

    CommandMatches(cmd, query)
    {
        local q := StrLower(query)
        if (InStr(StrLower(cmd.Title), q) || InStr(StrLower(cmd.Subtitle), q))
            return true
        for , kw in cmd.Keywords
        {
            if (InStr(StrLower(kw), q))
                return true
        }
        return false
    }

    UpdateListView()
    {
        this.ResultsList.Delete()
        for cmd in this.FilteredCommands
        {
            local icon := (cmd.Category = "Knowledge") ? "🧮" : "📋"
            this.ResultsList.Add("", icon, cmd.Title, cmd.Subtitle)
        }
        local count := this.FilteredCommands.Length
        local height := (count > 0) ? Min(count * 36, 280) : 0
        this.ResultsList.Move("", "", "", height)
        if (count > 0)
            this.ResultsList.Modify(1, "Select Focus")
        this.GUI.Show("NA AutoSize")
    }

    TryCalculate(expr)
    {
        if (!RegExMatch(expr, "[\+\-\*\/]"))
            return ""
        try
        {
            local sc := ComObjCreate("MSScriptControl.ScriptControl")
            sc.Language := "JScript"
            return sc.Eval(expr)
        }
        catch
            return ""
    }

    WM_KEYDOWN(wParam, lParam, msg, hwnd)
    {
        if (hwnd != this.GUI.Hwnd)
            return
        switch wParam
        {
        case 0x1B:
            this.Hide()
        case 0x0D:
            this.OnExecute()
        case 0x26:
            this.MoveSelection(-1)
        case 0x28:
            this.MoveSelection(1)
        }
    }

    MoveSelection(dir)
    {
        local count := this.FilteredCommands.Length
        if (count = 0)
            return
        local curr := this.ResultsList.GetNext(0, "F")
        if (curr = 0)
            curr := 1
        else
        {
            curr += dir
            if (curr < 1)
                curr := count
            else if (curr > count)
                curr := 1
        }
        this.ResultsList.Modify(0, "-Select")
        this.ResultsList.Modify(curr, "Select Focus")
    }

    OnExecute(*)
    {
        local row := this.ResultsList.GetNext(0, "F")
        if (row < 1 || row > this.FilteredCommands.Length)
            return
        local cmd := this.FilteredCommands[row]
        this.Hide()
        if (cmd.ExecuteFn)
            cmd.ExecuteFn()
    }

    DoTrim()
    {
        if (!this.Adapter)
            return
        local sel := this.Adapter.GetSelectionText()
        this.Adapter.ReplaceSelectionText(Trim(sel))
    }

    DoUpper()
    {
        if (!this.Adapter)
            return
        local sel := this.Adapter.GetSelectionText()
        this.Adapter.ReplaceSelectionText(StrUpper(sel))
    }

    DoLower()
    {
        if (!this.Adapter)
            return
        local sel := this.Adapter.GetSelectionText()
        this.Adapter.ReplaceSelectionText(StrLower(sel))
    }

    DoTitle()
    {
        if (!this.Adapter)
            return
        local sel := this.Adapter.GetSelectionText()
        if (sel = "")
            return
        local newText := RegExReplace(sel, "(?<!\w)(\w)", "$U1")
        this.Adapter.ReplaceSelectionText(newText)
    }

    DoSort()
    {
        if (!this.Adapter)
            return
        local sel := this.Adapter.GetSelectionText()
        if (sel = "")
            return
        local lines := StrSplit(sel, "`n", "`r")
        lines.Sort()
        this.Adapter.ReplaceSelectionText(lines.Join("`n"))
    }

    DoReverse()
    {
        if (!this.Adapter)
            return
        local sel := this.Adapter.GetSelectionText()
        if (sel = "")
            return
        local lines := StrSplit(sel, "`n", "`r")
        local reversed := Array()
        local i := lines.Length
        while (i > 0)
        {
            reversed.Push(lines[i])
            i--
        }
        this.Adapter.ReplaceSelectionText(reversed.Join("`n"))
    }

    DoCalculator()
    {
        ToolTip("Calculation executed")
        SetTimer(this.ClearTip.Bind(this), -1200)
    }

