        this.ops := Map()
        this.ops["upper"] := this.OpUpper.Bind(this)
        this.ops["lower"] := this.OpLower.Bind(this)
        this.ops["format"] := this.OpFormat.Bind(this)

        this.btnUpper.OnEvent("Click", this.HandleOp.Bind(this, "upper"))
        this.btnLower.OnEvent("Click", this.HandleOp.Bind(this, "lower"))
        this.btnFormat.OnEvent("Click", this.HandleOp.Bind(this, "format"))

        this.gui.OnEvent("Close", this.OnClose.Bind(this))
        this.gui.OnEvent("Escape", this.OnEscape.Bind(this))

        this.gui.Show("w610 h330")
        this.OnGuiShow()
    }

    __Delete() {
        try {
            if this.gui
                this.gui.Destroy()
        } catch as e {
            this.Log("Destroy failed: " e.Message)
        }
    }

    OnGuiShow(*) {
        clip := this.ReadClipboard()
        this.edit.Value := clip
    }

    OnEscape(*) {
        this.OnClose()
    }

    OnClose(*) {
        try {
            this.gui.Destroy()
        } catch as e {
            this.Log("Close failed: " e.Message)
        }
    }

    HandleOp(opName, ctrl, info) {
        text := this.edit.Value
        if !this.ops.Has(opName) {
            this.Log("Unknown op: " opName)
            return
        }

        fn := this.ops[opName]
        newText := fn.Call(text)
        this.edit.Value := newText
        this.WriteClipboard(newText)
    }

    ReadClipboard() {
        try {
            return A_Clipboard
        } catch as e {
            this.Log("Clipboard read failed: " e.Message)
            return ""
        }
    }

    WriteClipboard(text) {
        try {
            A_Clipboard := text
            return true
        } catch as e {
            this.Log("Clipboard write failed: " e.Message)
            MsgBox("Could not write to clipboard.", "Clipboard Error", 48)
            return false
        }
    }

    OpUpper(text) {
        return StrUpper(text)
    }

    OpLower(text) {
        return StrLower(text)
    }

    OpFormat(text) {
        normalized := StrReplace(text, "`r`n", "`n")
        normalized := StrReplace(normalized, "`r", "`n")

        lines := StrSplit(normalized, "`n")
        formatted := ""
        prevBlank := false

        for index, line in lines {
            line := StrReplace(line, "`t", "    ")
            line := RegExReplace(line, "\s+$")

            isBlank := (line = "")
            if isBlank {
                if prevBlank
                    continue
                prevBlank := true
            } else {
                prevBlank := false
            }

            if (formatted != "")
                formatted .= "`r`n"
            formatted .= line
        }

        return formatted
    }

    Log(msg) {
        try {
            OutputDebug(msg)
        } catch as e {
        }
        try {
            path := A_Temp "\ClipboardTextEditor.log"
            FileAppend(msg "`r`n", path, "UTF-8")
        } catch as e {
            OutputDebug("Log failed: " e.Message)
        }
    }
}

