class TextFormatter
{
    static ToUpperCase(text)
    {
        return StrUpper(text)
    }

    static ToLowerCase(text)
    {
        return StrLower(text)
    }

    static ToTitleCase(text)
    {
        local words, result, word
        words := StrSplit(text, " ")
        result := ""
        for word in words
        {
            if (word != "")
            {
                if (result != "")
                    result .= " "
                result .= StrUpper(SubStr(word, 1, 1)) . StrLower(SubStr(word, 2))
            }
        }
        return result
    }

    static RemoveExtraSpaces(text)
    {
        return RegExReplace(text, " +", " ")
    }

    static ReverseCase(text)
    {
        local result, i, char
        result := ""
        Loop Parse, text
        {
            char := A_LoopField
            if (char >= "A" && char <= "Z")
                result .= StrLower(char)
            else if (char >= "a" && char <= "z")
                result .= StrUpper(char)
            else
                result .= char
        }
        return result
    }

    static FormatAsCode(text)
    {
        local lines, result, line
        lines := StrSplit(text, "`n")
        result := ""
        for line in lines
        {
            if (result != "")
                result .= "`n"
            result .= "    " . line
        }
        return result
    }
}

