        try {
            originalText := this.editControl.Value
            transformedText := StrLower(originalText)
            this.editControl.Value := transformedText
            this.UpdateClipboard(transformedText)
            this.UpdateStatus("Converted to lowercase")
        } catch as err {
            this.HandleError("Case conversion failed: " err.Message)
        }
    }

    TransformToTitleCase(*) {
        try {
            originalText := this.editControl.Value
            words := StrSplit(originalText, " ")
            titleWords := []

            for index, word in words {
                if (StrLen(word) > 0) {
                    firstChar := StrUpper(SubStr(word, 1, 1))
                    restChars := StrLower(SubStr(word, 2))
                    titleWords.Push(firstChar . restChars)
                } else {
                    titleWords.Push(word)
                }
            }

            transformedText := Join(" ", titleWords*)
            this.editControl.Value := transformedText
            this.UpdateClipboard(transformedText)
            this.UpdateStatus("Converted to Title Case")
        } catch as err {
            this.HandleError("Title case conversion failed: " err.Message)
        }
    }

    UpdateClipboard(text) {
        try {
            A_Clipboard := text
            this.clipboardText := text
            this.UpdateStatus("Clipboard updated | Length: " StrLen(text) " characters")
        } catch as err {
            this.HandleError("Failed to update clipboard: " err.Message)
        }
    }

    HandleTextChange(*) {
        textLength := StrLen(this.editControl.Value)
        this.statusBar.SetText("Text modified | Length: " textLength " characters")
    }

    HandleClose(*) {
        this.gui.Destroy()
        ExitApp()
    }

    HandleError(message) {
        this.statusBar.SetText("Error: " message)
        OutputDebug("ClipboardEditor Error: " message "`n")
    }

    UpdateStatus(message) {
        this.statusBar.SetText(message)
    }
}

; Helper function to join array elements with separator
Join(separator, params*) {
    result := ""
    for index, param in params {
        if (index > 1) {
            result .= separator
        }
        result .= param
    }
    return result
}

