        if !this.gui
            this.CreateGui()
        this.LoadFromClipboard()
        this.gui.Show("w" . this.winW " h" . this.winH)
        this.edit.Focus()
    }

    Hide() {
        if this.gui
            this.gui.Hide()
    }

    Text {
        get => this.GetText()
        set => this.SetText(value)
    }

    CreateGui() {
        guiObj := Gui("+Resize +MinSize" this.winW "x" this.winH, "Clipboard Text Editor")
        guiObj.SetFont("s10")

        editCtrl := guiObj.Add("Edit", "x12 y12 w400 h200 WantTab")
        upperBtn := guiObj.Add("Button", "x12 y222 w120 h28", "Upper Case")
        lowerBtn := guiObj.Add("Button", "x142 y222 w120 h28", "Lower Case")
        titleBtn := guiObj.Add("Button", "x272 y222 w120 h28", "Title Case")

        guiObj.OnEvent("Close", this.OnClose.Bind(this))
        guiObj.OnEvent("Escape", this.OnClose.Bind(this))
        guiObj.OnEvent("Size", this.OnSize.Bind(this))

        upperBtn.OnEvent("Click", this.OnUpperClick.Bind(this))
        lowerBtn.OnEvent("Click", this.OnLowerClick.Bind(this))
        titleBtn.OnEvent("Click", this.OnTitleClick.Bind(this))

        editCtrl.OnEvent("Change", this.OnEditChange.Bind(this))

        this.gui := guiObj
        this.edit := editCtrl
        this.btnUpper := upperBtn
        this.btnLower := lowerBtn
        this.btnTitle := titleBtn

        this.Layout(this.winW, this.winH)
    }

    Layout(width, height) {
        marginX := 12
        marginY := 12
        spacingY := 10
        btnGap := 10
        btnH := 28

        editX := marginX
        editY := marginY
        editW := width - (marginX * 2)
        editH := height - (marginY * 2) - spacingY - btnH

        if (editW < 0)
            editW := 0
        if (editH < 0)
            editH := 0

        btnY := editY + editH + spacingY
        availableW := width - (marginX * 2)
        if (availableW < 0)
            availableW := 0

        btnW := Floor((availableW - (btnGap * 2)) / 3)
        if (btnW < 0)
            btnW := 0

        lastBtnW := availableW - (btnW * 2) - (btnGap * 2)
        if (lastBtnW < 0)
            lastBtnW := 0

        btn1X := marginX
        btn2X := btn1X + btnW + btnGap
        btn3X := btn2X + btnW + btnGap

        this.edit.Move(editX, editY, editW, editH)
        this.btnUpper.Move(btn1X, btnY, btnW, btnH)
        this.btnLower.Move(btn2X, btnY, btnW, btnH)
        this.btnTitle.Move(btn3X, btnY, lastBtnW, btnH)
    }

    LoadFromClipboard() {
        clipText := A_Clipboard
        this.SetText(clipText)
    }

    GetText() {
        if !this.edit
            return ""
        return this.edit.Value
    }

    SetText(text) {
        if !this.edit
            return
        if this.isUpdating
            return
        this.isUpdating := true
        this.edit.Value := text
        A_Clipboard := text
        this.isUpdating := false
    }

    ApplyTransform(transformName) {
        currentText := this.GetText()
        if (transformName = "upper")
            newText := StrUpper(currentText)
        else if (transformName = "lower")
            newText := StrLower(currentText)
        else if (transformName = "title")
            newText := this.ToTitleCase(currentText)
        else
            return
        this.SetText(newText)
    }

    ToTitleCase(text) {
        lowerText := StrLower(text)
        return RegExReplace(lowerText, "(*UCP)(?<!\pL)\pL", this.TitleCaseCb.Bind(this))
    }

    TitleCaseCb(match) {
        return StrUpper(match[0])
    }

    OnUpperClick(*) {
        this.ApplyTransform("upper")
    }

    OnLowerClick(*) {
        this.ApplyTransform("lower")
    }

    OnTitleClick(*) {
        this.ApplyTransform("title")
    }

    OnEditChange(*) {
        if this.isUpdating
            return
        editText := this.edit.Value
        this.isUpdating := true
        A_Clipboard := editText
        this.isUpdating := false
    }

    OnSize(guiObj, minMax, width, height) {
        if (minMax = -1)
            return
        this.Layout(width, height)
    }

    OnClose(*) {
        if this.gui {
            this.gui.Destroy()
            this.gui := 0
            this.edit := 0
            this.btnUpper := 0
            this.btnLower := 0
            this.btnTitle := 0
        }
    }
}

