      this.Status.Color := "C5C8C6"

      this.LoadInitialText()
      this.UpdateStatus()
      this.Gui.Show("w450 h500", "Clipboard Formatter")
   }

   LoadInitialText() {
      local clipboard := A_Clipboard
      if (clipboard != "") {
         this.CurrentText := clipboard
         this.Edit.Control.Value := clipboard
      } else {
         this.Edit.Control.Value := "Clipboard is empty or contains non-text data."
      }
   }

   Transform(mode, ctl) {
      local transformed := ""
      if (mode == "Upper")
         transformed := StrUpper(this.Edit.Control.Value)
      else if (mode == "Lower")
         transformed := StrLower(this.Edit.Control.Value)
      else if (mode == "Proper")
         transformed := StrTitle(this.Edit.Control.Value)

      if (transformed != "") {
         this.UndoStack := [this.Edit.Control.Value] ; Reset undo stack
         this.RedoStack := [] ; Clear redo stack
         this.Edit.Control.Value := transformed
         A_Clipboard := transformed
         this.CurrentText := transformed
         this.UpdateStatus()
         this.UpdateUndoRedoButtons()
      }
   }

   Undo(ctl := "") {
      if this.UndoStack.Length > 0 {
         local currentText := this.Edit.Control.Value
         this.RedoStack.Push(currentText)
         this.Edit.Control.Value := this.UndoStack.Pop()
         this.CurrentText := this.Edit.Control.Value
         A_Clipboard := this.CurrentText
         this.UpdateStatus()
         this.UpdateUndoRedoButtons()
      }
   }

   Redo(ctl := "") {
      if this.RedoStack.Length > 0 {
         local currentText := this.Edit.Control.Value
         this.UndoStack.Push(currentText)
         this.Edit.Control.Value := this.RedoStack.Pop()
         this.CurrentText := this.Edit.Control.Value
         A_Clipboard := this.CurrentText
         this.UpdateStatus()
         this.UpdateUndoRedoButtons()
      }
   }

   UpdateUndoRedoButtons() {
      this.UndoButton.Control.Opt(this.UndoStack.Length > 0 ? "-Disabled" : "+Disabled")
      this.RedoButton.Control.Opt(this.RedoStack.Length > 0 ? "-Disabled" : "+Disabled")
   }

   EditChange(ctl) {
      this.CurrentText := ctl.Value
      this.UpdateStatus()
   }

   UpdateStatus() {
      local charCount := StrLen(this.CurrentText)
      local lineCount := StrCount(this.CurrentText, "`n") + 1
