class ClipboardEditor {
    __New() {
        this.clipboardText := ""
        this.gui := Gui()
        this.edit := this.gui.Add("Edit", "w500 h300 vText")
        this.upperBtn := this.gui.Add("Button", "w100 h30 x10 y320", "UPPERCASE")
        this.lowerBtn := this.gui.Add("Button", "w100 h30 x120 y320", "lowercase")
        this.titleBtn := this.gui.Add("Button", "w100 h30 x230 y320", "Title Case")
        this.saveBtn := this.gui.Add("Button", "w100 h30 x340 y320", "Save to Clipboard")

        this.upperBtn.OnEvent("Click", this.UpperCase.Bind(this))
        this.lowerBtn.OnEvent("Click", this.LowerCase.Bind(this))
        this.titleBtn.OnEvent("Click", this.TitleCase.Bind(this))
        this.saveBtn.OnEvent("Click", this.SaveToClipboard.Bind(this))

        this.gui.OnEvent("Close", this.GuiClose.Bind(this))
        this.gui.Show()
        this.LoadClipboard()
    }

    LoadClipboard() {
        try {
            this.clipboardText := ClipboardAll()
            if (this.clipboardText = "")
                this.clipboardText := "Clipboard is empty"
            this.edit.Value := this.clipboardText
        } catch {
            this.edit.Value := "Error accessing clipboard"
        }
    }

    UpperCase() {
        this.edit.Value := StrUpper(this.edit.Value)
    }

    LowerCase() {
        this.edit.Value := StrLower(this.edit.Value)
    }

    TitleCase() {
        text := this.edit.Value
        words := StrSplit(text, " `t`n")
        result := ""
        for word in words {
            if (word != "")
                result .= StrUpper(SubStr(word, 1, 1)) . StrLower(SubStr(word, 2)) . " "
        }
        this.edit.Value := Trim(result)
    }

    SaveToClipboard() {
        try {
            Clipboard := this.edit.Value
            MsgBox("Text saved to clipboard!")
        } catch {
            MsgBox("Error saving to clipboard")
        }
    }

    GuiClose() {
        ExitApp()
    }
}

