class ClipboardFormatter {
    GuiRef := 0
    Edit := 0
    UpperBtn := 0
    LowerBtn := 0
    TitleBtn := 0
    UndoBtn := 0
    RedoBtn := 0
    Status := 0

    History := []
    HistoryIndex := -1
    CurrentText := ""

    __New() {
        this.GuiRef := Gui("-MinimizeBox +Resize +AlwaysOnTop", "Clipboard Formatter")
        this.GuiRef.OnEvent("Close", (*) => ExitApp)
        this.GuiRef.OnEvent("Escape", (*) => this.Close())
        this.GuiRef.OnEvent("Size", (*) => this.Resize())
        this.GuiRef.OnEvent("Key", this.KeyHandler.Bind(this))

        this.Edit := new EditWrap(this.GuiRef, "WorkingText", 10, 10, 400, 150)
        this.Edit.Create()
        this.Edit.OnChange(this.TextChanged)

        this.UpperBtn := new ButtonWrap(this.GuiRef, "UpperBtn", 10, 170, 100, 25, "UPPER CASE")
        this.UpperBtn.Create()
        this.UpperBtn.OnClick(this.ToUpper)

        this.LowerBtn := new ButtonWrap(this.GuiRef, "LowerBtn", 120, 170, 100, 25, "lower case")
        this.LowerBtn.Create()
        this.LowerBtn.OnClick(this.ToLower)

        this.TitleBtn := new ButtonWrap(this.GuiRef, "TitleBtn", 230, 170, 100, 25, "Proper Case")
        this.TitleBtn.Create()
        this.TitleBtn.OnClick(this.ToTitle)

        this.UndoBtn := new ButtonWrap(this.GuiRef, "UndoBtn", 10, 210, 100, 25, "Undo")
        this.UndoBtn.Create()
        this.UndoBtn.OnClick(this.Undo)

        this.RedoBtn := new ButtonWrap(this.GuiRef, "RedoBtn", 120, 210, 100, 25, "Redo")
        this.RedoBtn.Create()
        this.RedoBtn.OnClick(this.Redo)

        this.Status := this.GuiRef.Add("Static", 10 "|" 250 " w550 h20, "")

        this.GuiRef.Show("AutoSize")

        this.LoadClipboard()
        this.UpdateStatus()
        this.UpdateUndoRedoState()
    }

    LoadClipboard() {
        clipType := ClipboardAll
        if (ClipboardType = "Text" || Clipboard != "") {
            this.CurrentText := Clipboard
            this.Edit.SetValue(this.CurrentText)
            this.History.Push(this.CurrentText)
            this.HistoryIndex := 0
        } else {
            this.CurrentText := ""
            this.Edit.SetValue("")
            this.History.Push("")
            this.HistoryIndex := 0
            this.Status.Text := "Clipboard is empty or contains non-text data"
        }
    }

    ToUpper() {
        this.Transform(StrUpper(this.CurrentText))
    }

    ToLower() {
        this.Transform(StrLower(this.CurrentText))
    }

    ToTitle() {
        this.Transform(StrTitle(this.CurrentText))
    }

    Transform(newText) {
        this.CurrentText := newText
        this.Edit.SetValue(this.CurrentText)
        Clipboard := this.CurrentText
        this.AddToHistory()
        this.UpdateStatus()
        this.UpdateUndoRedoState()
    }

    AddToHistory() {
        if (this.HistoryIndex < this.History.Length - 1) {
            this.History := this.History[1..this.HistoryIndex + 1]
        }
        this.History.Push(this.CurrentText)
        this.HistoryIndex := this.History.Length - 1
    }

    Undo() {
        if (this.HistoryIndex > 0) {
            this.HistoryIndex--
            this.CurrentText := this.History[this.HistoryIndex + 1]
            this.Edit.SetValue(this.CurrentText)
            Clipboard := this.CurrentText
            this.UpdateStatus()
            this.UpdateUndoRedoState()
        }
    }

    Redo() {
        if (this.HistoryIndex < this.History.Length - 1) {
            this.HistoryIndex++
            this.CurrentText := this.History[this.HistoryIndex + 1]
            this.Edit.SetValue(this.CurrentText)
            Clipboard := this.CurrentText
            this.UpdateStatus()
            this.UpdateUndoRedoState()
        }
    }

    TextChanged() {
        this.CurrentText := this.Edit.GetValue()
        this.UpdateStatus()
    }

    UpdateStatus() {
        charCount := StrLen(this.CurrentText)
        lineCount := 1
        if (this.CurrentText != "") {
            lineCount := StrReplace(this.CurrentText, "`n", "`n").Length - StrReplace(this.CurrentText, "`n", "").Length + 1
        }
        this.Status.Text := "Characters: " charCount " | Lines: " lineCount
    }

    UpdateUndoRedoState() {
        canUndo := this.HistoryIndex > 0
        canRedo := this.HistoryIndex < this.History.Length - 1

        this.UndoBtn.SetEnabled(canUndo)
        this.RedoBtn.SetEnabled(canRedo)
    }

    Resize() {
    }

    KeyHandler(e) {
        if (e.Name = "z" && GetKeyState("Ctrl", "P")) {
            this.Undo()
        } else if (e.Name = "y" && GetKeyState("Ctrl", "P")) {
            this.Redo()
        }
    }

    Close() {
        this.GuiRef.Destroy()
        ExitApp
    }

    __Delete() {
        if this.GuiRef {
            this.GuiRef.Destroy()
        }
    }
}

