      if this.history.Count() > 1 {
         this.redoStack.Push(this.history.Pop())
         this.edit.SetValue(this.history.Peek())
         Clipboard := this.edit.GetValue()
         this.UpdateStatus()
         this.UpdateButtons()
      }
   }

   Redo() {
