         this.history.Push(this.redoStack.Pop())
         this.edit.SetValue(this.history.Peek())
         Clipboard := this.edit.GetValue()
         this.UpdateStatus()
         this.UpdateButtons()
      }
   }

   UpdateStatus() {
      text := this.edit.GetValue()
      lines := StrSplit(text, "`n").Length()
      chars := StrLen(text)
      this.status.Opt("Text", "Chars: " chars " Lines: " lines)
   }

   UpdateButtons() {
      this.undoBtn.control.Opt("Enabled", this.history.Count() > 1)
      this.redoBtn.control.Opt("Enabled", this.redoStack.Count() > 0)
   }

   Resize() {
      this.edit.control.Move(null, null, "w" this.gui.Width-40, "h" this.gui.Height-100)
      this.status.Move(null, "y" this.gui.Height-40)
   }

   Close() {
      this.gui.Destroy()
   }

