        if (!ClipWait(0.5)) {
            this.currentText := ""
            this.editCtrl.Set("")
            this.lastMessage := "Clipboard is empty. Paste text and refresh."
        } else if (this.IsText(Clipboard)) {
            this.currentText := Clipboard
            this.editCtrl.Set(this.currentText)
            this.lastMessage := ""
        } else {
            this.currentText := ""
            this.editCtrl.Set("")
            this.lastMessage := "Clipboard does not contain text."
        }
        this.UpdateStatus()
        this.UpdateTitle()
    }

    IsText(text) {
        return Type(text) = "String" || Type(text) = "Buffer"
    }

    UpdateTitle() {
        if (this.lastMessage != "")
            this.gui.Title := "Clipboard Text Formatter - " this.lastMessage
        else
            this.gui.Title := "Clipboard Text Formatter"
    }

    UpdateStatus() {
        local chars := StrLen(this.currentText)
        local lines := StrSplit(this.currentText, "`n").Length
        this.gui.Controls["Status"].Value := "Chars: " chars " | Lines: " lines
    }

    ToUpper(*) {
        this.Transform(StrUpper(this.currentText))
    }

    ToLower(*) {
        this.Transform(StrLower(this.currentText))
    }

    ToProper(*) {
        this.Transform(StrTitle(this.currentText))
    }

    Transform(newText) {
        this.history.Push(this.currentText)
        this.redoStack := []

        this.currentText := newText
        this.editCtrl.Set(this.currentText)
        this.UpdateStatus()

        Clipboard := newText

        this.UpdateButtonStates()
    }

    Undo(*) {
        if (this.history.Length = 0)
            return

        this.redoStack.Push(this.currentText)

        this.currentText := this.history.Pop()
        this.editCtrl.Set(this.currentText)
        this.UpdateStatus()
        Clipboard := this.currentText

        this.UpdateButtonStates()
    }

    Redo(*) {
        if (this.redoStack.Length = 0)
            return

        this.history.Push(this.currentText)

        this.currentText := this.redoStack.Pop()
        this.editCtrl.Set(this.currentText)
        this.UpdateStatus()
        Clipboard := this.currentText

        this.UpdateButtonStates()
    }

