class ClipboardEditor {
    __New() {
        this.history := []
        this.historyIndex := -1

        this.g := Gui().Show("w600 h400", "Clipboard Formatter")
        this.g.OnEvent("Close", this.OnClose.Bind(this))
        this.g.OnEvent("Size", this.OnResize.Bind(this))

        this.textEdit := this.g.Add("Edit", "x10 y10 w-20 h-100 R3 HScroll")
        this.status := this.g.Add("Text", "x10 y-30 w-20 vStatus")

        this.upperBtn := this.g.Add("Button", "x10 y-90 w60")
        this.lowerBtn := this.g.Add("Button", "x+5 y-90 w60")
        this.properBtn := this.g.Add("Button", "x+5 y-90 w60")
        this.undoBtn := this.g.Add("Button", "x10 y-60 w60")
        this.redoBtn := this.g.Add("Button", "x+5 y-60 w60")

        this.editWrap := EditWrap(this.textEdit, "MainText")
        this.upperBtnWrap := ButtonWrap(this.upperBtn, "Upper")
        this.lowerBtnWrap := ButtonWrap(this.lowerBtn, "Lower")
        this.properBtnWrap := ButtonWrap(this.properBtn, "Proper")
        this.undoBtnWrap := ButtonWrap(this.undoBtn, "Undo")
        this.redoBtnWrap := ButtonWrap(this.redoBtn, "Redo")

        this.upperBtnWrap.AttachAction(this.OnTransform.Bind(this, "upper"))
        this.lowerBtnWrap.AttachAction(this.OnTransform.Bind(this, "lower"))
        this.properBtnWrap.AttachAction(this.OnTransform.Bind(this, "proper"))
        this.undoBtnWrap.AttachAction(this.OnUndo.Bind(this))
        this.redoBtnWrap.AttachAction(this.OnRedo.Bind(this))

        this.textEdit.OnEvent("Change", this.editWrap.UpdateStats.Bind(this.editWrap))

        this.LoadClipboard()
        this.UpdateUI()
    }

    LoadClipboard() {
        try {
            ClipboardAll := ClipboardAll()
            if (InStr(ClipboardAll.Format, "Text") && ClipboardAll.Text) {
                this.editWrap.SetText(ClipboardAll.Text)
                this.history := [this.editWrap.GetText()]
                this.historyIndex := 0
            } else {
                MsgBox("Clipboard contains non-text data")
            }
        } catch {
            MsgBox("Failed to read clipboard")
        }
    }

    OnTransform(caseType) {
        text := this.editWrap.GetText()
        transformed := caseType == "upper"? StrUpper(text)
                   : caseType == "lower"? StrLower(text)
                   : StrTitle(text)

        this.history.InsertAt(A_Index() + this.historyIndex, transformed)
        this.historyIndex := this.history.Length()
        this.editWrap.SetText(transformed)
        ClipboardSet(transformed)
        this.editWrap.UpdateStats()
        this.UpdateUI()
    }

    OnUndo() {
        if (this.historyIndex > 0) {
            this.historyIndex--
            this.editWrap.SetText(this.history[this.historyIndex])
            ClipboardSet(this.history[this.historyIndex])
            this.editWrap.UpdateStats()
            this.UpdateUI()
        }
    }

    OnRedo() {
        if (this.historyIndex < this.history.Length() - 1) {
            this.historyIndex++
            this.editWrap.SetText(this.history[this.historyIndex])
            ClipboardSet(this.history[this.historyIndex])
            this.editWrap.UpdateStats()
            this.UpdateUI()
        }
    }

    UpdateUI() {
        this.undoBtnWrap.Enable(this.historyIndex > 0)
        this.redoBtnWrap.Enable(this.historyIndex < this.history.Length() - 1)
    }

    OnResize(w, h) {
        this.textEdit.SetBounds("x10 y10 w" (w-20) " h" (h-110))
        this.status.SetBounds("x10 y" (h-30) " w" (w-20))
        this.upperBtn.SetBounds("x10 y" (h-90))
        this.lowerBtn.SetBounds("x+5 y" (h-90))
        this.properBtn.SetBounds("x+5 y" (h-90))
        this.undoBtn.SetBounds("x10 y" (h-60))
        this.redoBtn.SetBounds("x+5 y" (h-60))
    }

    OnClose() {
        try {
            if (this.g.hWnd) {
                this.g.Close()
            }
        } catch {
            ExitApp
        }
    }

    __Delete() {
        this.g := ""
    }
}

