#Requires AutoHotkey v2.1-alpha.16
#SingleInstance Force

editor := ClipboardFormatter()

class ControlWrapper {
    control := ""
    hwnd := ""

    __New(gui, type, options, text, x, y, w, h) {
        this.control := gui.AddControl(type, options " x" x " y" y " w" w " h" h, text)
        this.hwnd := this.control.Hwnd
        this.AfterCreate()
    }

    AfterCreate() {
    }
}

class EditWrap extends ControlWrapper {
    AfterCreate() {
    }

    GetText() {
        return this.control.Value
    }

    SetText(text) {
        this.control.Value := text
    }

    GetLineCount() {
        return this.control.LineCount
    }

    GetCharCount() {
        return StrLen(this.control.Value)
    }
}

class ButtonWrap extends ControlWrapper {
    AfterCreate() {
    }

    SetOnClick(callback) {
        this.control.OnEvent("Click", callback)
    }

    SetEnabled(enabled) {
        this.control.Opt(enabled ? "+Enabled" : "-Enabled")
    }
}

class ClipboardFormatter {
    gui := ""
    editWrap := ""
    btnUpper := ""
    btnLower := ""
    btnProper := ""
    btnUndo := ""
    btnRedo := ""
    statusText := ""
    history := []
    historyIndex := -1
    currentText := ""

    __New() {
        this.gui := Gui()
        this.gui.Title := "Clipboard Text Formatter"
        this.gui.OnEvent("Close", this.OnClose.Bind(this))
        this.gui.OnEvent("Escape", this.OnEscape.Bind(this))

        this.editWrap := EditWrap(this.gui, "Edit", "Multi", "", 10, 10, 380, 200)
        this.editWrap.control.OnEvent("Change", this.OnEditChange.Bind(this))
        this.editWrap.control.OnEvent("KeyDown", this.OnKeyDown.Bind(this))

        this.btnUpper := ButtonWrap(this.gui, "Button", "", "UPPER CASE", 10, 220, 100, 30)
        this.btnUpper.SetOnClick(this.ApplyTransform.Bind(this, "UPPER"))

        this.btnLower := ButtonWrap(this.gui, "Button", "", "lower case", 120, 220, 100, 30)
        this.btnLower.SetOnClick(this.ApplyTransform.Bind(this, "LOWER"))

        this.btnProper := ButtonWrap(this.gui, "Button", "", "Proper Case", 230, 220, 100, 30)
        this.btnProper.SetOnClick(this.ApplyTransform.Bind(this, "PROPER"))

        this.btnUndo := ButtonWrap(this.gui, "Button", "", "Undo", 10, 260, 80, 30)
        this.btnUndo.SetOnClick(this.Undo.Bind(this))

        this.btnRedo := ButtonWrap(this.gui, "Button", "", "Redo", 100, 260, 80, 30)
        this.btnRedo.SetOnClick(this.Redo.Bind(this))

        this.statusText := this.gui.AddText("x10 y300 w380", "Status: Ready")

        this.history := []
        this.historyIndex := -1

        this.LoadClipboard()
        this.gui.Show()
    }

    LoadClipboard() {
        clipContent := ""
        try {
            temp := A_Clipboard
            if IsString(temp) {
                clipContent := temp
            } else {
                this.SetStatus("Clipboard does not contain text")
            }
        } catch e {
            this.SetStatus("Error accessing clipboard: " e.Message)
        }

        this.InitializeHistory(clipContent)
        this.editWrap.SetText(clipContent)
        this.UpdateStatus()
        this.UpdateUndoRedoButtons()
    }

    InitializeHistory(initialText) {
        this.history := [initialText]
        this.historyIndex := 0
        this.currentText := initialText
    }

    UpdateHistory(newText) {
        if (this.currentText = newText) {
            return
        }

        if (this.historyIndex < this.history.Length - 1) {
            this.history.RemoveAt(this.historyIndex + 1, this.history.Length - this.historyIndex - 1)
        }

        this.history.Push(newText)
        this.historyIndex := this.history.Length - 1
        this.currentText := newText
    }

    ApplyTransform(transformType) {
        text := this.editWrap.GetText()

        switch transformType {
            case "UPPER":
                transformed := StrUpper(text)
            case "LOWER":
                transformed := StrLower(text)
            case "PROPER":
                transformed := StrTitle(text)
            default:
                return
        }

        this.editWrap.SetText(transformed)
        this.UpdateHistory(transformed)
        this.UpdateStatus()
        this.UpdateUndoRedoButtons()

        try {
            A_Clipboard := transformed
            this.SetStatus("Transformed and copied to clipboard")
        } catch e {
            this.SetStatus("Error writing to clipboard: " e.Message)
        }
    }

    Undo() {
        if (this.historyIndex <= 0) {
            return
        }

        this.historyIndex--
        this.currentText := this.history[this.historyIndex]
        this.editWrap.SetText(this.currentText)
        this.UpdateStatus()
        this.UpdateUndoRedoButtons()
        this.SetStatus("Undone")
    }

    Redo() {
        if (this.historyIndex >= this.history.Length - 1) {
            return
        }

        this.historyIndex++
        this.currentText := this.history[this.historyIndex]
        this.editWrap.SetText(this.currentText)
        this.UpdateStatus()
        this.UpdateUndoRedoButtons()
        this.SetStatus("Redone")
    }

    OnEditChange() {
        newText := this.editWrap.GetText()
        this.UpdateHistory(newText)
        this.UpdateStatus()
        this.UpdateUndoRedoButtons()
    }

    OnKeyDown(key, info) {
        if (info.Ctrl && key = "z") {
            this.Undo()
            return 1
        }
        if (info.Ctrl && key = "y") {
            this.Redo()
            return 1
        }
    }

    UpdateStatus() {
        charCount := this.editWrap.GetCharCount()
        lineCount := this.editWrap.GetLineCount()
        this.SetStatus("Chars: " charCount " | Lines: " lineCount)
    }

    UpdateUndoRedoButtons() {
        canUndo := this.historyIndex > 0
        canRedo := this.historyIndex < this.history.Length - 1

        this.btnUndo.SetEnabled(canUndo)
        this.btnRedo.SetEnabled(canRedo)
    }

    SetStatus(message) {
        this.statusText.Value := "Status: " message
    }

    OnEscape() {
        this.gui.Destroy()
    }

    OnClose() {
        this.gui.Destroy()
    }

    __Delete() {
        try this.gui.Destroy()
    }
}

