[ClipboardEditor] {
   __New() {
      this.history := Map()
      this.historyIndex := -1
      this.currentText := ""
      this.initGUI()
   }

   initGUI() {
      Gui := Gui.New("Clipboard Formatter", 400, 300)
      Gui.DarkMode := true

      this.editWrap := EditWrap.New(Gui, "edit", "Clipboard Text", 10, 10, 380, 200)
      this.editWrap.OnEvent("TextChange", this.updateText)

      this.upperBtn := ButtonWrap.New(Gui, "upperBtn", "UPPER CASE", 10, 220, 100, 30)
      this.upperBtn.OnClick := this.transformText.bind(this, "StrUpper")

      this.lowerBtn := ButtonWrap.New(Gui, "lowerBtn", "LOWER CASE", 120, 220, 100, 30)
      this.lowerBtn.OnClick := this.transformText.bind(this, "StrLower")

      this.properBtn := ButtonWrap.New(Gui, "properBtn", "PROPER CASE", 230, 220, 100, 30)
      this.properBtn.OnClick := this.transformText.bind(this, "StrTitle")

      this.undoBtn := ButtonWrap.New(Gui, "undoBtn", "UNDO (Ctrl+Z)", 10, 260, 100, 30)
      this.undoBtn.OnClick := this.undo.bind(this)
      Gui.OnKeyDown := this.handleKeyDown.bind(this)

      this.redoBtn := ButtonWrap.New(Gui, "redoBtn", "REDO (Ctrl+Y)", 120, 260, 100, 30)
      this.redoBtn.OnClick := this.redo.bind(this)

      this.statusLabel := Gui.New("statusLabel", "Status: Ready", 10, 290, 380, 20)
      Gui.Show()
   }

   updateText() {
      this.currentText := this.editWrap.Value
      this.historyIndex := this.history.Count
      this.history["" . this.historyIndex] := this.currentText
      this.updateStatus()
   }

   transformText(transform) {
      if (this.historyIndex < this.history.Count - 1) {
         this.historyIndex++
         this.editWrap.Value := this.history["" . this.historyIndex]
         this.updateStatus()
      }
   }

   undo() {
      if (this.historyIndex > 0) {
         this.historyIndex--
         this.editWrap.Value := this.history["" . this.historyIndex]
         this.updateStatus()
      }
   }

   redo() {
      if (this.historyIndex < this.history.Count - 1) {
         this.historyIndex++
         this.editWrap.Value := this.history["" . this.historyIndex]
         this.updateStatus()
      }
   }

   handleKeyDown(e) {
      if (e.Key == "z" && e.Control) {
         this.undo()
      } else if (e.Key == "y" && e.Control) {
         this.redo()
      } else if (e.Key == "Escape") {
         Gui.Close()
      }
   }

   updateStatus() {
      this.statusLabel.Text := "Status: " . StrLen(this.currentText) . " chars, " . StrSplit(this.currentText, "`n").Count . " lines"
   }

   __Delete() {
      Gui.Close()
   }
}

class EditWrap {
   __New(parent, id, text, x, y, w, h) {
      this.parent := parent
      Gui := Gui.New(id, "", text, x, y, w, h)
      Gui.Opt("AutoSizeText", true)
      Gui.Opt("Editable", true)
      this.value := text
      Gui.OnEvent("TextChange", this.onTextChange.bind(this))
      Gui.Show()
   }

   get Value() {
      return this.value
   }

   set Value(val) {
      this.value := val
   }

   onTextChange() {
      this.parent.updateText()
   }
}

class ButtonWrap {
   __New(parent, id, text, x, y, w, h) {
      Gui := Gui.New(id, "", text, x, y, w, h)
      Gui.Opt("ButtonColor", "#0078D7")
      Gui.Opt("TextColor", "White")
      Gui.Opt("Enabled", true)
      this.parent.OnClick := this.onClick.bind(this)
      Gui.Show()
   }

   onClick() {
      this.parent.OnClick()
   }
}

